{
  "name": "Arix Signature Christmas Tree",
  "description": "A high-fidelity, luxury 3D interactive experience featuring a morphing gold and emerald Christmas tree."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import * as THREE from 'three';

export enum TreeState {
  SCATTERED = 'SCATTERED',
  TREE_SHAPE = 'TREE_SHAPE',
}

export interface DualPosition {
  tree: THREE.Vector3;
  scatter: THREE.Vector3;
  rotation: THREE.Euler;
  scale: number;
  speed: number; // For individual flutter speed
}

export type OrnamentType = 'SPHERE' | 'BOX';

export interface OrnamentData extends DualPosition {
  type: OrnamentType;
  color: THREE.Color;
}

import * as THREE from 'three';

// Constants
export const TREE_HEIGHT = 12;
export const TREE_RADIUS_BOTTOM = 5.5;
export const SCATTER_RADIUS = 15;

/**
 * Generates a random point inside a sphere
 */
export const getScatterPoint = (radius: number = SCATTER_RADIUS): THREE.Vector3 => {
  const u = Math.random();
  const v = Math.random();
  const theta = 2 * Math.PI * u;
  const phi = Math.acos(2 * v - 1);
  const r = Math.cbrt(Math.random()) * radius;

  const x = r * Math.sin(phi) * Math.cos(theta);
  const y = r * Math.sin(phi) * Math.sin(theta);
  const z = r * Math.cos(phi);

  return new THREE.Vector3(x, y, z);
};

/**
 * Generates a point on a cone surface (The Tree)
 * Uses spiral distribution for better aesthetics
 */
export const getTreePoint = (height: number = TREE_HEIGHT, radius: number = TREE_RADIUS_BOTTOM, yOffset: number = -height/2): THREE.Vector3 => {
  // Normalized height (0 at bottom, 1 at top)
  const h = Math.random(); 
  const y = h * height;

  // Radius at this height
  const r = radius * (1 - h);

  // Angle (Spiral)
  const angle = h * 25 + Math.random() * Math.PI * 2;

  const x = r * Math.cos(angle);
  const z = r * Math.sin(angle);

  return new THREE.Vector3(x, y + yOffset, z);
};

export const randomRange = (min: number, max: number) => Math.random() * (max - min) + min;

import React, { useMemo, useRef } from 'react';
import { useFrame } from '@react-three/fiber';
import * as THREE from 'three';
import { getScatterPoint, getTreePoint } from '../utils/math';
import { TreeState } from '../types';

// Custom Shader Material for the Foliage
// This handles the interpolation on the GPU for maximum performance
const FoliageShaderMaterial = {
  uniforms: {
    uTime: { value: 0 },
    uMorphFactor: { value: 0 }, // 0 = Scatter, 1 = Tree
    uColorBase: { value: new THREE.Color('#004225') }, // Deep Emerald
    uColorTip: { value: new THREE.Color('#D4AF37') }, // Gold
  },
  vertexShader: `
    uniform float uTime;
    uniform float uMorphFactor;
    attribute vec3 aTreePosition;
    attribute vec3 aScatterPosition;
    attribute float aRandom;
    attribute float aSize;

    varying vec3 vColor;
    varying float vAlpha;

    // Cubic easing for smoother transition
    float easeInOutCubic(float x) {
      return x < 0.5 ? 4.0 * x * x * x : 1.0 - pow(-2.0 * x + 2.0, 3.0) / 2.0;
    }

    void main() {
      // Ease the morph factor
      float t = easeInOutCubic(uMorphFactor);

      // Mix positions based on morph factor
      vec3 targetPos = mix(aScatterPosition, aTreePosition, t);

      // Add "Breathing" / "Floating" animation
      // The closer to Tree state (t=1), the smaller the noise (tighter structure)
      // The closer to Scatter (t=0), the larger the floating
      float noiseAmp = mix(1.0, 0.2, t); 
      targetPos.x += sin(uTime * 1.5 + aRandom * 10.0) * 0.1 * noiseAmp;
      targetPos.y += cos(uTime * 1.2 + aRandom * 20.0) * 0.1 * noiseAmp;
      targetPos.z += sin(uTime * 1.8 + aRandom * 5.0) * 0.1 * noiseAmp;

      vec4 mvPosition = modelViewMatrix * vec4(targetPos, 1.0);
      gl_Position = projectionMatrix * mvPosition;

      // Size attenuation
      gl_PointSize = aSize * (300.0 / -mvPosition.z);

      // Pass randomness to fragment
      vAlpha = 0.6 + 0.4 * sin(uTime * 2.0 + aRandom * 100.0);
    }
  `,
  fragmentShader: `
    uniform vec3 uColorBase;
    uniform vec3 uColorTip;
    varying float vAlpha;

    void main() {
      // Create a soft circular particle
      vec2 coord = gl_PointCoord - vec2(0.5);
      float dist = length(coord);

      if (dist > 0.5) discard;

      // Soft glow gradient
      float strength = 1.0 - (dist * 2.0);
      strength = pow(strength, 1.5);

      // Mix colors (center is gold/bright, edge is emerald)
      vec3 color = mix(uColorBase, uColorTip, strength * 0.5);

      // Add extra brightness for bloom
      gl_FragColor = vec4(color * 2.0, vAlpha * strength);
    }
  `
};

interface FoliageProps {
  count?: number;
  state: TreeState;
}

export const Foliage: React.FC<FoliageProps> = ({ count = 6000, state }) => {
  const shaderRef = useRef<THREE.ShaderMaterial>(null);

  // Generate data once
  const { positions, treePositions, scatterPositions, randoms, sizes } = useMemo(() => {
    const positions = new Float32Array(count * 3);
    const treePositions = new Float32Array(count * 3);
    const scatterPositions = new Float32Array(count * 3);
    const randoms = new Float32Array(count);
    const sizes = new Float32Array(count);

    for (let i = 0; i < count; i++) {
      // Tree coords
      const tPos = getTreePoint();
      treePositions[i * 3] = tPos.x;
      treePositions[i * 3 + 1] = tPos.y;
      treePositions[i * 3 + 2] = tPos.z;

      // Scatter coords
      const sPos = getScatterPoint();
      scatterPositions[i * 3] = sPos.x;
      scatterPositions[i * 3 + 1] = sPos.y;
      scatterPositions[i * 3 + 2] = sPos.z;

      randoms[i] = Math.random();
      sizes[i] = Math.random() * 0.5 + 0.2; // Size variance
    }

    return { positions, treePositions, scatterPositions, randoms, sizes };
  }, [count]);

  useFrame((stateThree, delta) => {
    if (shaderRef.current) {
      shaderRef.current.uniforms.uTime.value = stateThree.clock.elapsedTime;

      // Smoothly interpolate morph factor
      const targetFactor = state === TreeState.TREE_SHAPE ? 1.0 : 0.0;
      const currentFactor = shaderRef.current.uniforms.uMorphFactor.value;

      // Linear interpolation with damping
      const speed = 2.0;
      shaderRef.current.uniforms.uMorphFactor.value = THREE.MathUtils.lerp(
        currentFactor,
        targetFactor,
        speed * delta
      );
    }
  });

  return (
    <points>
      <bufferGeometry>
        <bufferAttribute
          attach="attributes-position"
          count={positions.length / 3}
          array={positions} // Initial dummy positions, shader handles mix
          itemSize={3}
        />
        <bufferAttribute
          attach="attributes-aTreePosition"
          count={treePositions.length / 3}
          array={treePositions}
          itemSize={3}
        />
        <bufferAttribute
          attach="attributes-aScatterPosition"
          count={scatterPositions.length / 3}
          array={scatterPositions}
          itemSize={3}
        />
        <bufferAttribute
          attach="attributes-aRandom"
          count={randoms.length}
          array={randoms}
          itemSize={1}
        />
        <bufferAttribute
          attach="attributes-aSize"
          count={sizes.length}
          array={sizes}
          itemSize={1}
        />
      </bufferGeometry>
      <shaderMaterial
        ref={shaderRef}
        args={[FoliageShaderMaterial]}
        transparent
        depthWrite={false}
        blending={THREE.AdditiveBlending}
      />
    </points>
  );
};

import React, { useMemo, useRef, useLayoutEffect } from 'react';
import { useFrame } from '@react-three/fiber';
import * as THREE from 'three';
import { getScatterPoint, getTreePoint, randomRange } from '../utils/math';
import { TreeState, OrnamentData } from '../types';

const tempObj = new THREE.Object3D();
const tempVec3 = new THREE.Vector3();

interface OrnamentsProps {
  count?: number;
  state: TreeState;
}

export const Ornaments: React.FC<OrnamentsProps> = ({ count = 300, state }) => {
  const meshRef = useRef<THREE.InstancedMesh>(null);
  const boxesRef = useRef<THREE.InstancedMesh>(null);

  // Separate data for spheres (balls) and boxes (gifts)
  const sphereData = useMemo(() => generateOrnamentData(count, 'SPHERE'), [count]);
  const boxData = useMemo(() => generateOrnamentData(Math.floor(count / 4), 'BOX'), [count]);

  useLayoutEffect(() => {
    // Set initial colors
    if (meshRef.current) applyColors(meshRef.current, sphereData);
    if (boxesRef.current) applyColors(boxesRef.current, boxData);
  }, [sphereData, boxData]);

  useFrame((rootState, delta) => {
    const time = rootState.clock.elapsedTime;
    const targetMorph = state === TreeState.TREE_SHAPE ? 1 : 0;

    // We update matrices manually in JS. 
    // This is performant enough for < 1000 instances and simpler than custom shader injection for PBR materials.

    // Update Spheres
    updateInstances(meshRef.current, sphereData, targetMorph, time, delta);

    // Update Boxes
    updateInstances(boxesRef.current, boxData, targetMorph, time, delta);
  });

  return (
    <group>
      {/* Spheres: Glossy Gold and Red */}
      <instancedMesh ref={meshRef} args={[undefined, undefined, sphereData.length]}>
        <sphereGeometry args={[0.25, 32, 32]} />
        <meshStandardMaterial 
          metalness={0.9} 
          roughness={0.1} 
          envMapIntensity={2}
        />
      </instancedMesh>

      {/* Boxes: Gifts */}
      <instancedMesh ref={boxesRef} args={[undefined, undefined, boxData.length]}>
        <boxGeometry args={[0.4, 0.4, 0.4]} />
        <meshStandardMaterial 
          metalness={0.6} 
          roughness={0.3}
          envMapIntensity={1.5}
        />
      </instancedMesh>
    </group>
  );
};

// --- Helpers ---

function generateOrnamentData(count: number, type: 'SPHERE' | 'BOX'): OrnamentData[] {
  const data: OrnamentData[] = [];
  const colors = [
    new THREE.Color('#FFD700'), // Gold
    new THREE.Color('#C41E3A'), // Cardinal Red
    new THREE.Color('#E5E4E2'), // Platinum
    new THREE.Color('#B8860B'), // Dark Goldenrod
  ];

  for (let i = 0; i < count; i++) {
    const treePos = getTreePoint(12, 5.0, -6);
    // Push ornaments slightly outward so they sit ON the leaves, not inside
    const radialDir = new THREE.Vector3(treePos.x, 0, treePos.z).normalize();
    treePos.add(radialDir.multiplyScalar(0.4)); 

    const scatterPos = getScatterPoint(20);

    data.push({
      type,
      tree: treePos,
      scatter: scatterPos,
      rotation: new THREE.Euler(Math.random() * Math.PI, Math.random() * Math.PI, 0),
      scale: randomRange(0.8, 1.5),
      speed: randomRange(0.5, 2.0),
      color: colors[Math.floor(Math.random() * colors.length)]
    });
  }
  return data;
}

function applyColors(mesh: THREE.InstancedMesh, data: OrnamentData[]) {
  for (let i = 0; i < data.length; i++) {
    mesh.setColorAt(i, data[i].color);
  }
  mesh.instanceColor!.needsUpdate = true;
}

function updateInstances(
  mesh: THREE.InstancedMesh | null, 
  data: OrnamentData[], 
  targetMorph: number, 
  time: number,
  delta: number
) {
  if (!mesh) return;

  // We use a static variable on the mesh to track current morph state purely for smoothing
  // In a rigorous ECS this would be separate, but here we can just lerp positions directly

  // NOTE: To get a true "state machine" transition feel, we re-calculate the interpolated position every frame.
  // We use a global "morphProgress" that we would ideally track. 
  // However, simpler approach: Each instance tracks its own interpolated position via lerp.
  // But since we can't store state on the instance easily without overhead, 
  // we just calculate: Position = Mix(Scatter, Tree, SmoothMorphValue)

  // Let's approximate a smooth global transition variable derived from `targetMorph`
  // We can't easily store a "currentMorph" ref for the whole group inside this loop function cleanly without closures.
  // Instead, we assume the parent passed a precise morph value? 
  // No, the parent passes 0 or 1. We need to smooth it.

  // Actually, let's just do a stateless mix based on a smoothed global value if we had one.
  // Since we don't, we'll do a per-instance approach which looks organic (some arrive faster).

  // Let's use a "time-based" wave for transition to make it look magical?
  // Or simple lerp.

  // We will assume the mesh.userData stores the current transition value.
  if (mesh.userData.morphValue === undefined) mesh.userData.morphValue = 0;

  const speed = 1.5;
  mesh.userData.morphValue = THREE.MathUtils.lerp(mesh.userData.morphValue, targetMorph, speed * delta);
  const t = mesh.userData.morphValue;

  for (let i = 0; i < data.length; i++) {
    const item = data[i];

    // Position Mix
    tempVec3.lerpVectors(item.scatter, item.tree, t);

    // Add noise/floating
    const floatAmp = (1 - t) * 0.5; // Floats more when scattered
    tempVec3.y += Math.sin(time * item.speed + i) * floatAmp;
    tempVec3.x += Math.cos(time * item.speed * 0.5 + i) * floatAmp;

    // Rotation
    // Spin when scattered, stabilize when tree
    const rotX = item.rotation.x + (time * 0.2 * (1 - t));
    const rotY = item.rotation.y + (time * 0.5 * (1 - t));

    tempObj.position.copy(tempVec3);
    tempObj.rotation.set(rotX, rotY, item.rotation.z);
    tempObj.scale.setScalar(item.scale * (t * 0.5 + 0.5)); // Grow slightly when forming tree

    tempObj.updateMatrix();
    mesh.setMatrixAt(i, tempObj.matrix);
  }
  mesh.instanceMatrix.needsUpdate = true;
}

import React, { useRef } from 'react';
import { useFrame, useThree } from '@react-three/fiber';
import { OrbitControls, Environment, PerspectiveCamera, Stars, Float } from '@react-three/drei';
import { EffectComposer, Bloom, Vignette, Noise } from '@react-three/postprocessing';
import * as THREE from 'three';
import { Foliage } from './Foliage';
import { Ornaments } from './Ornaments';
import { TreeState } from '../types';

interface ExperienceProps {
  treeState: TreeState;
}

export const Experience: React.FC<ExperienceProps> = ({ treeState }) => {
  const cameraRef = useRef<THREE.PerspectiveCamera>(null);
  const groupRef = useRef<THREE.Group>(null);

  useFrame((state) => {
    // Subtle continuous rotation of the whole tree group
    if (groupRef.current) {
        groupRef.current.rotation.y = state.clock.elapsedTime * 0.05;
    }
  });

  return (
    <>
      <PerspectiveCamera makeDefault position={[0, 2, 25]} fov={50} ref={cameraRef} />

      {/* Controls: Restricted to keep the best angle */}
      <OrbitControls 
        enablePan={false} 
        minPolarAngle={Math.PI / 3} 
        maxPolarAngle={Math.PI / 1.8}
        minDistance={10}
        maxDistance={40}
      />

      {/* Lighting: Dramatic & Warm */}
      <ambientLight intensity={0.2} color="#001a10" />
      <spotLight 
        position={[10, 20, 10]} 
        angle={0.5} 
        penumbra={1} 
        intensity={2} 
        color="#fffaed" 
        castShadow 
      />
      <pointLight position={[-10, 5, -10]} intensity={1.5} color="#D4AF37" />
      <pointLight position={[0, -5, 10]} intensity={0.5} color="#004225" />

      {/* Environment for reflections on metallic ornaments */}
      <Environment preset="city" />

      {/* Background Ambience */}
      <Stars radius={100} depth={50} count={5000} factor={4} saturation={0} fade speed={1} />

      <group ref={groupRef} position={[0, -4, 0]}>
        {/* Central glowing core helper (optional, adds depth) */}
        <pointLight position={[0, 6, 0]} intensity={1} color="#ffaa00" distance={10} decay={2} />

        {/* The Tree Components */}
        <Foliage state={treeState} count={12000} />
        <Ornaments state={treeState} count={600} />

        {/* Topper Star */}
        <Float speed={2} rotationIntensity={0.5} floatIntensity={0.5}>
            <mesh position={[0, 12.5, 0]} scale={treeState === TreeState.TREE_SHAPE ? 1 : 0}>
                <dodecahedronGeometry args={[0.8, 0]} />
                <meshStandardMaterial 
                    color="#FFD700" 
                    emissive="#FFD700" 
                    emissiveIntensity={2} 
                    roughness={0} 
                    metalness={1} 
                />
            </mesh>
        </Float>
      </group>

      {/* Post Processing for the "Cinematic Glow" */}
      <EffectComposer disableNormalPass>
        <Bloom 
          luminanceThreshold={0.8} 
          mipmapBlur 
          intensity={1.5} 
          radius={0.4} 
        />
        <Vignette eskil={false} offset={0.1} darkness={1.1} />
        <Noise opacity={0.02} /> 
      </EffectComposer>
    </>
  );
};

import React from 'react';
import { TreeState } from '../types';

