          </span>
        </button>

        <p className="font-sans text-xs tracking-widest opacity-50 uppercase">
          {isTree ? 'Interactive Mode: Formed' : 'Interactive Mode: Ethereal'}
        </p>
      </div>

      {/* Footer */}
      <footer className="flex justify-between items-end">
        <div className="text-xs font-sans text-white/40 tracking-wider">
          <p>EST. 2024</p>
          <p>LIMITED EDITION</p>
        </div>
        <div className="text-right">
             <div className="w-12 h-[1px] bg-[#D4AF37] mb-2 ml-auto opacity-50"></div>
             <p className="text-xs font-serif italic text-[#D4AF37] opacity-80">
                "Experience the elegance of algorithms."
             </p>
        </div>
      </footer>
    </div>
