import React, { useState, Suspense } from 'react';
import { Canvas } from '@react-three/fiber';
import { Loader } from '@react-three/drei';
import { Experience } from './components/Experience';
import { Overlay } from './components/Overlay';
import { TreeState } from './types';

function App() {
  const [treeState, setTreeState] = useState<TreeState>(TreeState.SCATTERED);

  const toggleState = () => {
    setTreeState((prev) => 
      prev === TreeState.TREE_SHAPE ? TreeState.SCATTERED : TreeState.TREE_SHAPE
    );
  };

  return (
    <div className="relative w-full h-screen bg-[#000805]">
      <Canvas
        dpr={[1, 2]} // Optimize pixel ratio for performance
        gl={{ 
          antialias: false, // Post-processing handles AA usually, or better performance without 
          powerPreference: "high-performance",
          toneMapping: 3, // CineonToneMapping
          toneMappingExposure: 1.5
        }} 
      >
        <Suspense fallback={null}>
          <Experience treeState={treeState} />
        </Suspense>
      </Canvas>

      {/* Standard Drei Loader */}
      <Loader 
        containerStyles={{ background: '#000805' }}
        innerStyles={{ width: '200px', height: '2px', background: '#333' }}
        barStyles={{ height: '2px', background: '#D4AF37' }}
        dataStyles={{ fontSize: '10px', fontFamily: 'sans-serif', color: '#D4AF37', letterSpacing: '0.2em' }}
      />

      <Overlay treeState={treeState} toggleState={toggleState} />
    </div>
  );
}

export default App;

import * as THREE from 'three';

export enum TreeState {
  SCATTERED = 'SCATTERED',
  TREE_SHAPE = 'TREE_SHAPE',
}

export interface DualPosition {
  tree: THREE.Vector3;
  scatter: THREE.Vector3;
  rotation: THREE.Euler;
  scale: number;
  speed: number; // For individual flutter speed
}

export type OrnamentType = 'SPHERE' | 'BOX';

export interface OrnamentData extends DualPosition {
  type: OrnamentType;
  color: THREE.Color;
}

export interface UserPhotoData extends DualPosition {
  id: string;
  url: string;
}

import React, { useMemo, useRef, useState, useEffect } from 'react';
import { useFrame, useLoader } from '@react-three/fiber';
import * as THREE from 'three';
import { getScatterPoint, getTreePoint, randomRange } from '../utils/math';
import { TreeState, UserPhotoData } from '../types';

interface UserPhotosProps {
  photos: string[];
  state: TreeState;
}

// Sub-component for individual photo to handle texture loading gracefully
const PhotoFrame: React.FC<{ data: UserPhotoData; state: TreeState }> = ({ data, state }) => {
  const groupRef = useRef<THREE.Group>(null);
  const texture = useLoader(THREE.TextureLoader, data.url);

  // Create a local morph value for smooth transition
  const morphRef = useRef(0);

  useFrame((rootState, delta) => {
    if (!groupRef.current) return;

    const time = rootState.clock.elapsedTime;
    const targetMorph = state === TreeState.TREE_SHAPE ? 1 : 0;

    // Smooth lerp for state transition
    const speed = 1.5;
    morphRef.current = THREE.MathUtils.lerp(morphRef.current, targetMorph, speed * delta);
    const t = morphRef.current;

    // Position Mix
    const currentPos = new THREE.Vector3().lerpVectors(data.scatter, data.tree, t);

    // Add float animation
    const floatAmp = (1 - t) * 0.5;
    currentPos.y += Math.sin(time * data.speed) * floatAmp;
    currentPos.x += Math.cos(time * data.speed * 0.5) * floatAmp;

    // Rotation Mix
    // Spin freely when scattered, face outward/upright when in tree
    const targetRot = data.rotation; // Base rotation
    // Calculate "Looking at center" rotation for tree mode? 
    // For simplicity, we use the pre-calculated random rotation but stabilize it.

    const rotX = data.rotation.x + (time * 0.2 * (1 - t));
    const rotY = data.rotation.y + (time * 0.3 * (1 - t));
    const rotZ = data.rotation.z * (1 - t); // Upright (z=0) when t=1

    groupRef.current.position.copy(currentPos);
    groupRef.current.rotation.set(rotX, rotY, rotZ);

    // Scale up slightly when in tree mode
    const scale = data.scale * (0.8 + 0.2 * t);
    groupRef.current.scale.setScalar(scale);
  });

  return (
    <group ref={groupRef}>
      {/* Gold Frame */}
      <mesh position={[0, 0, -0.05]}>
        <boxGeometry args={[1.2, 1.2, 0.1]} />
        <meshStandardMaterial 
            color="#D4AF37" 
            metalness={0.8} 
            roughness={0.2} 
            envMapIntensity={2} 
        />
      </mesh>

      {/* The Photo */}
      <mesh>
        <planeGeometry args={[1, 1]} />
        <meshBasicMaterial map={texture} side={THREE.DoubleSide} />
      </mesh>
    </group>
