export const Experience: React.FC<ExperienceProps> = ({ treeState, userPhotos }) => {
  const cameraRef = useRef<THREE.PerspectiveCamera>(null);
  const groupRef = useRef<THREE.Group>(null);
  const starRef = useRef<THREE.Mesh>(null);

  // Generate 5-pointed Star Shape
  const starShape = useMemo(() => {
    const shape = new THREE.Shape();
    const outerRadius = 1.5;
    const innerRadius = 0.7; // Depth of the star cuts
    const points = 5;

    for (let i = 0; i < points * 2; i++) {
      const angle = (i * Math.PI) / points;
      const radius = i % 2 === 0 ? outerRadius : innerRadius;
      const x = Math.cos(angle) * radius;
      const y = Math.sin(angle) * radius;
      if (i === 0) shape.moveTo(x, y);
      else shape.lineTo(x, y);
    }
    shape.closePath();
    return shape;
  }, []);

  const starExtrudeSettings = useMemo(() => ({
    depth: 0.5,
    bevelEnabled: true,
    bevelThickness: 0.1,
    bevelSize: 0.1,
    bevelSegments: 2
  }), []);

  useFrame((state) => {
    // Subtle continuous rotation of the whole tree group
    if (groupRef.current) {
        groupRef.current.rotation.y = state.clock.elapsedTime * 0.05;
    }

    // Specific Star Rotation (Y-axis slow spin)
    if (starRef.current) {
        starRef.current.rotation.y += 0.01;
    }
  });

  return (
    <>
      <PerspectiveCamera makeDefault position={[0, 2, 25]} fov={50} ref={cameraRef} />

      {/* Controls: Restricted to keep the best angle */}
      <OrbitControls 
        enablePan={false} 
        minPolarAngle={Math.PI / 3} 
        maxPolarAngle={Math.PI / 1.8}
        minDistance={10}
        maxDistance={40}
      />

      {/* Lighting: Dramatic & Warm */}
      <ambientLight intensity={0.2} color="#001a10" />
      <spotLight 
        position={[10, 20, 10]} 
        angle={0.5} 
        penumbra={1} 
        intensity={2} 
        color="#fffaed" 
        castShadow 
      />
      <pointLight position={[-10, 5, -10]} intensity={1.5} color="#D4AF37" />
      <pointLight position={[0, -5, 10]} intensity={0.5} color="#004225" />

      {/* Environment for reflections on metallic ornaments */}
      <Environment preset="city" />

      {/* Background Ambience */}
      <Stars radius={100} depth={50} count={5000} factor={4} saturation={0} fade speed={1} />

      <group ref={groupRef} position={[0, -4, 0]}>
        {/* Central glowing core helper (optional, adds depth) */}
        <pointLight position={[0, 6, 0]} intensity={1} color="#ffaa00" distance={10} decay={2} />

        {/* The Tree Components */}
        <Foliage state={treeState} count={12000} />
        <Ornaments state={treeState} count={600} />

        {/* User Uploaded Photos "Cloud" */}
        <UserPhotos photos={userPhotos} state={treeState} />

        {/* Topper Star - Pentagram */}
        <group position={[0, 12.5, 0]}>
            <mesh 
                ref={starRef} 
                scale={treeState === TreeState.TREE_SHAPE ? 1 : 0}
                // Rotate 90deg on X so it faces forward initially (Extrude draws on XY plane)
                // Then the useFrame rotates Y to spin it
                rotation={[0, 0, Math.PI / 10]} 
            >
                <extrudeGeometry args={[starShape, starExtrudeSettings]} />
                <meshStandardMaterial 
                    color="#ffea00" 
                    emissive="#ffea00" 
                    emissiveIntensity={2.0} 
                    toneMapped={false}
                />
                <pointLight color="#ffea00" distance={30} intensity={5} decay={2} />
            </mesh>
        </group>
      </group>

      {/* Post Processing for the "Cinematic Glow" */}
      <EffectComposer disableNormalPass>
        <Bloom 
          luminanceThreshold={0.8} 
          mipmapBlur 
          intensity={1.5} 
          radius={0.4} 
        />
        <Vignette eskil={false} offset={0.1} darkness={1.1} />
        <Noise opacity={0.02} /> 
      </EffectComposer>
    </>
  );
};

import React, { useMemo, useRef, useEffect } from 'react';
import { useFrame, useLoader, useThree } from '@react-three/fiber';
import * as THREE from 'three';
import { getScatterPoint, getTreePoint, randomRange } from '../utils/math';
import { TreeState, UserPhotoData } from '../types';

interface UserPhotosProps {
  photos: string[];
  state: TreeState;
}

// Sub-component for individual photo to handle texture loading gracefully
const PhotoFrame: React.FC<{ data: UserPhotoData; state: TreeState }> = ({ data, state }) => {
  const groupRef = useRef<THREE.Group>(null);
  const texture = useLoader(THREE.TextureLoader, data.url);
  const { gl } = useThree();

  // Fix Texture Flickering / Aliasing
  useEffect(() => {
    if (texture) {
      texture.generateMipmaps = true;
      texture.minFilter = THREE.LinearMipmapLinearFilter; // High quality reduction
      texture.magFilter = THREE.LinearFilter;
      texture.anisotropy = gl.capabilities.getMaxAnisotropy(); // Sharp at angles
      texture.needsUpdate = true;
    }
  }, [texture, gl]);

  // Create a local morph value for smooth transition
  const morphRef = useRef(0);

  useFrame((rootState, delta) => {
    if (!groupRef.current) return;

    const time = rootState.clock.elapsedTime;
    const targetMorph = state === TreeState.TREE_SHAPE ? 1 : 0;

    // Smooth lerp for state transition
    const speed = 1.5;
    morphRef.current = THREE.MathUtils.lerp(morphRef.current, targetMorph, speed * delta);
    const t = morphRef.current;

    // Position Mix
    const currentPos = new THREE.Vector3().lerpVectors(data.scatter, data.tree, t);

    // Add float animation
    const floatAmp = (1 - t) * 0.5;
    currentPos.y += Math.sin(time * data.speed) * floatAmp;
    currentPos.x += Math.cos(time * data.speed * 0.5) * floatAmp;

    // Rotation Mix
    const rotX = data.rotation.x + (time * 0.2 * (1 - t));
    const rotY = data.rotation.y + (time * 0.3 * (1 - t));
    const rotZ = data.rotation.z * (1 - t); 

    groupRef.current.position.copy(currentPos);
    groupRef.current.rotation.set(rotX, rotY, rotZ);

    // Scale up slightly when in tree mode
    const scale = data.scale * (0.8 + 0.2 * t);
    groupRef.current.scale.setScalar(scale);
  });

  return (
    <group ref={groupRef}>
      {/* Gold Frame */}
      {/* Moved slightly back (-0.06) to ensure separation from photo at 0 */}
      <mesh position={[0, 0, -0.06]}>
        <boxGeometry args={[1.2, 1.2, 0.1]} />
        <meshStandardMaterial 
            color="#D4AF37" 
            metalness={0.8} 
            roughness={0.2} 
            envMapIntensity={2} 
        />
      </mesh>

      {/* The Photo */}
      {/* Photo plane sits exactly at 0, Frame is behind. */}
      <mesh position={[0, 0, 0]}>
        <planeGeometry args={[1, 1]} />
        <meshBasicMaterial map={texture} side={THREE.DoubleSide} />
      </mesh>
    </group>
  );
};

export const UserPhotos: React.FC<UserPhotosProps> = ({ photos, state }) => {
  // Generate 3D data for photos only when the photo list changes
  const photosData = useMemo(() => {
    return photos.map((url, index) => {
      // Position photos in the middle-to-bottom section of the tree for better visibility
      const treePos = getTreePoint(10, 5, -5); 
      // Push slightly out so they don't clip inside leaves
      const radialDir = new THREE.Vector3(treePos.x, 0, treePos.z).normalize();
      treePos.add(radialDir.multiplyScalar(0.8));

      return {
        id: `photo-${index}`,
        url,
        tree: treePos,
        scatter: getScatterPoint(18),
        rotation: new THREE.Euler(0, Math.random() * Math.PI * 2, 0), // Mostly upright y-rotation
        scale: randomRange(0.8, 1.2),
        speed: randomRange(0.5, 1.5),
      } as UserPhotoData;
    });
  }, [photos]);

  return (
    <group>
      {photosData.map((data) => (
        <PhotoFrame key={data.id} data={data} state={state} />
      ))}
    </group>
  );
};

import React, { useMemo, useRef, useLayoutEffect } from 'react';
import { useFrame } from '@react-three/fiber';
import * as THREE from 'three';
import { getScatterPoint, getTreePoint, randomRange } from '../utils/math';
import { TreeState, OrnamentData } from '../types';

const tempObj = new THREE.Object3D();
const tempVec3 = new THREE.Vector3();

interface OrnamentsProps {
  count?: number;
  state: TreeState;
}

export const Ornaments: React.FC<OrnamentsProps> = ({ count = 300, state }) => {
  const meshRef = useRef<THREE.InstancedMesh>(null);
  const purpleRef = useRef<THREE.InstancedMesh>(null);
  const boxesRef = useRef<THREE.InstancedMesh>(null);

  // 1. Standard Sphere Colors (Gold, Red, Platinum)
  const sphereColors = useMemo(() => [
    new THREE.Color('#FFD700'), // Gold
    new THREE.Color('#C41E3A'), // Cardinal Red
    new THREE.Color('#E5E4E2'), // Platinum
  ], []);

  // 2. New Special Color (Starry Purple)
  const purpleColor = useMemo(() => [
     new THREE.Color('#4B0082') // Indigo / Deep Purple
  ], []);

  // Separate data generation
  const sphereData = useMemo(() => generateOrnamentData(Math.floor(count * 0.7), 'SPHERE', sphereColors), [count, sphereColors]);
  const purpleData = useMemo(() => generateOrnamentData(Math.floor(count * 0.3), 'SPHERE', purpleColor), [count, purpleColor]);
  const boxData = useMemo(() => generateOrnamentData(Math.floor(count / 4), 'BOX', [
      new THREE.Color('#D4AF37'), 
      new THREE.Color('#C41E3A')
  ]), [count]);

  useLayoutEffect(() => {
    // Set initial colors
    if (meshRef.current) applyColors(meshRef.current, sphereData);
    if (purpleRef.current) applyColors(purpleRef.current, purpleData);
    if (boxesRef.current) applyColors(boxesRef.current, boxData);
  }, [sphereData, purpleData, boxData]);

  useFrame((rootState, delta) => {
    const time = rootState.clock.elapsedTime;
    const targetMorph = state === TreeState.TREE_SHAPE ? 1 : 0;

    // Update Standard Spheres
    updateInstances(meshRef.current, sphereData, targetMorph, time, delta);

    // Update Purple Spheres
    updateInstances(purpleRef.current, purpleData, targetMorph, time, delta);

    // Update Boxes
    updateInstances(boxesRef.current, boxData, targetMorph, time, delta);
  });

  return (
    <group>
      {/* 1. Standard Spheres: Glossy Gold/Red/Platinum */}
      <instancedMesh ref={meshRef} args={[undefined, undefined, sphereData.length]}>
        <sphereGeometry args={[0.25, 32, 32]} />
        <meshStandardMaterial 
          metalness={0.9} 
          roughness={0.1} 
          envMapIntensity={2}
        />
      </instancedMesh>

      {/* 2. Special Purple Spheres: Matte Physical Material */}
      <instancedMesh ref={purpleRef} args={[undefined, undefined, purpleData.length]}>
        <sphereGeometry args={[0.25, 32, 32]} />
        {/* Requested properties: Roughness 0.4, Metalness 0.6 */}
        <meshPhysicalMaterial 
          metalness={0.6} 
          roughness={0.4} 
          envMapIntensity={1.5}
          clearcoat={0.2}
          clearcoatRoughness={0.1}
        />
      </instancedMesh>

      {/* 3. Boxes: Gifts */}
      <instancedMesh ref={boxesRef} args={[undefined, undefined, boxData.length]}>
        <boxGeometry args={[0.4, 0.4, 0.4]} />
        <meshStandardMaterial 
          metalness={0.6} 
          roughness={0.3}
          envMapIntensity={1.5}
        />
      </instancedMesh>
    </group>
  );
};

// --- Helpers ---

function generateOrnamentData(count: number, type: 'SPHERE' | 'BOX', colorPalette: THREE.Color[]): OrnamentData[] {
  const data: OrnamentData[] = [];

  for (let i = 0; i < count; i++) {
    const treePos = getTreePoint(12, 5.0, -6);
    // Push ornaments slightly outward so they sit ON the leaves, not inside
    const radialDir = new THREE.Vector3(treePos.x, 0, treePos.z).normalize();
    treePos.add(radialDir.multiplyScalar(0.4)); 

    const scatterPos = getScatterPoint(20);

    data.push({
      type,
      tree: treePos,
      scatter: scatterPos,
      rotation: new THREE.Euler(Math.random() * Math.PI, Math.random() * Math.PI, 0),
      scale: randomRange(0.8, 1.5),
      speed: randomRange(0.5, 2.0),
      color: colorPalette[Math.floor(Math.random() * colorPalette.length)]
    });
  }
  return data;
}

function applyColors(mesh: THREE.InstancedMesh, data: OrnamentData[]) {
  for (let i = 0; i < data.length; i++) {
    mesh.setColorAt(i, data[i].color);
  }
  mesh.instanceColor!.needsUpdate = true;
}

function updateInstances(
  mesh: THREE.InstancedMesh | null, 
  data: OrnamentData[], 
  targetMorph: number, 
  time: number,
  delta: number
) {
  if (!mesh) return;

  if (mesh.userData.morphValue === undefined) mesh.userData.morphValue = 0;

  const speed = 1.5;
  mesh.userData.morphValue = THREE.MathUtils.lerp(mesh.userData.morphValue, targetMorph, speed * delta);
  const t = mesh.userData.morphValue;

  for (let i = 0; i < data.length; i++) {
    const item = data[i];

    // Position Mix
    tempVec3.lerpVectors(item.scatter, item.tree, t);

    // Add noise/floating
    const floatAmp = (1 - t) * 0.5; // Floats more when scattered
    tempVec3.y += Math.sin(time * item.speed + i) * floatAmp;
    tempVec3.x += Math.cos(time * item.speed * 0.5 + i) * floatAmp;

    // Rotation
    // Spin when scattered, stabilize when tree
    const rotX = item.rotation.x + (time * 0.2 * (1 - t));
    const rotY = item.rotation.y + (time * 0.5 * (1 - t));

    tempObj.position.copy(tempVec3);
    tempObj.rotation.set(rotX, rotY, item.rotation.z);
    tempObj.scale.setScalar(item.scale * (t * 0.5 + 0.5)); // Grow slightly when forming tree

    tempObj.updateMatrix();
    mesh.setMatrixAt(i, tempObj.matrix);
  }
  mesh.instanceMatrix.needsUpdate = true;
}

import * as THREE from 'three';

// Constants
export const TREE_HEIGHT = 12;
export const TREE_RADIUS_BOTTOM = 5.5;
export const SCATTER_RADIUS = 15;

/**
 * Generates a random point inside a sphere
 */
export const getScatterPoint = (radius: number = SCATTER_RADIUS): THREE.Vector3 => {
  const u = Math.random();
  const v = Math.random();
  const theta = 2 * Math.PI * u;
  const phi = Math.acos(2 * v - 1);
  const r = Math.cbrt(Math.random()) * radius;

  const x = r * Math.sin(phi) * Math.cos(theta);
  const y = r * Math.sin(phi) * Math.sin(theta);
  const z = r * Math.cos(phi);

  return new THREE.Vector3(x, y, z);
};

/**
 * Generates a point on a cone surface (The Tree) with Organic Volume Scattering
 * Replaces strict spiral with random volume distribution
 */
export const getTreePoint = (height: number = TREE_HEIGHT, radius: number = TREE_RADIUS_BOTTOM, yOffset: number = -height/2): THREE.Vector3 => {
  // 1. Random Height (0 to 1)
  const h = Math.random(); 
  const y = h * height + yOffset;

  // 2. Max Radius at this height
  const maxR = radius * (1 - h);

  // 3. Random Radius with bias away from center (Volume Scattering)
  // bias: ensures tree isn't hollow but also not too dense at center (which simple random would do)
  // Using sqrt(random) gives uniform distribution on a disk.
  // We offset min radius slightly to ensure core density isn't infinite and looks 'branchy'
  const r = maxR * (0.2 + 0.8 * Math.sqrt(Math.random()));

  // 4. Random Angle
  const theta = Math.random() * Math.PI * 2;

  const x = r * Math.cos(theta);
  const z = r * Math.sin(theta);

  return new THREE.Vector3(x, y, z);
};

export const randomRange = (min: number, max: number) => Math.random() * (max - min) + min;

import React, { useMemo, useRef } from 'react';
import { useFrame } from '@react-three/fiber';
import * as THREE from 'three';
import { getScatterPoint, getTreePoint, TREE_HEIGHT } from '../utils/math';
import { TreeState } from '../types';

// Custom Shader Material for the Foliage
// This handles the interpolation on the GPU for maximum performance
const FoliageShaderMaterial = {
  uniforms: {
    uTime: { value: 0 },
    uMorphFactor: { value: 0 }, // 0 = Scatter, 1 = Tree
    uColorBase: { value: new THREE.Color('#004225') }, // Deep Emerald
    uColorTip: { value: new THREE.Color('#D4AF37') }, // Gold
  },
  vertexShader: `
    uniform float uTime;
    uniform float uMorphFactor;
    attribute vec3 aTreePosition;
    attribute vec3 aScatterPosition;
    attribute float aRandom;
    attribute float aSize;

    varying vec3 vColor;
    varying float vAlpha;

    // Cubic easing for smoother transition
    float easeInOutCubic(float x) {
      return x < 0.5 ? 4.0 * x * x * x : 1.0 - pow(-2.0 * x + 2.0, 3.0) / 2.0;
    }

    void main() {
      // Ease the morph factor
      float t = easeInOutCubic(uMorphFactor);

      // Mix positions based on morph factor
      vec3 targetPos = mix(aScatterPosition, aTreePosition, t);

      // Add "Breathing" / "Floating" animation
      // The closer to Tree state (t=1), the smaller the noise (tighter structure)
      // The closer to Scatter (t=0), the larger the floating
      float noiseAmp = mix(1.0, 0.2, t); 
      targetPos.x += sin(uTime * 1.5 + aRandom * 10.0) * 0.1 * noiseAmp;
      targetPos.y += cos(uTime * 1.2 + aRandom * 20.0) * 0.1 * noiseAmp;
      targetPos.z += sin(uTime * 1.8 + aRandom * 5.0) * 0.1 * noiseAmp;

      vec4 mvPosition = modelViewMatrix * vec4(targetPos, 1.0);
      gl_Position = projectionMatrix * mvPosition;

      // Size attenuation
      gl_PointSize = aSize * (300.0 / -mvPosition.z);

      // Pass randomness to fragment
      vAlpha = 0.6 + 0.4 * sin(uTime * 2.0 + aRandom * 100.0);
    }
  `,
  fragmentShader: `
    uniform vec3 uColorBase;
    uniform vec3 uColorTip;
    varying float vAlpha;

    void main() {
      // Create a soft circular particle
      vec2 coord = gl_PointCoord - vec2(0.5);
      float dist = length(coord);

      if (dist > 0.5) discard;

      // Soft glow gradient
      float strength = 1.0 - (dist * 2.0);
      strength = pow(strength, 1.5);

      // Mix colors (center is gold/bright, edge is emerald)
      vec3 color = mix(uColorBase, uColorTip, strength * 0.5);

      // Add extra brightness for bloom
      gl_FragColor = vec4(color * 2.0, vAlpha * strength);
    }
  `
};

interface FoliageProps {
  count?: number;
  state: TreeState;
}

export const Foliage: React.FC<FoliageProps> = ({ count = 6000, state }) => {
  const shaderRef = useRef<THREE.ShaderMaterial>(null);

  // Generate data once
  const { positions, treePositions, scatterPositions, randoms, sizes } = useMemo(() => {
    const positions = new Float32Array(count * 3);
    const treePositions = new Float32Array(count * 3);
    const scatterPositions = new Float32Array(count * 3);
    const randoms = new Float32Array(count);
    const sizes = new Float32Array(count);

    const yOffset = -TREE_HEIGHT / 2;

    for (let i = 0; i < count; i++) {
      // Tree coords
      const tPos = getTreePoint();
      treePositions[i * 3] = tPos.x;
      treePositions[i * 3 + 1] = tPos.y;
      treePositions[i * 3 + 2] = tPos.z;

      // Scatter coords
      const sPos = getScatterPoint();
      scatterPositions[i * 3] = sPos.x;
      scatterPositions[i * 3 + 1] = sPos.y;
      scatterPositions[i * 3 + 2] = sPos.z;

      randoms[i] = Math.random();

      // Size Gradient Logic
      // Normalized height 0 (bottom) to 1 (top)
      const h = (tPos.y - yOffset) / TREE_HEIGHT;
      // Formula: 0.8 at top, 1.2 at bottom
      const scaleGradient = 0.8 + 0.4 * (1 - h);

      // Base random size * gradient
      sizes[i] = (Math.random() * 0.5 + 0.2) * scaleGradient;
    }

    return { positions, treePositions, scatterPositions, randoms, sizes };
  }, [count]);

  useFrame((stateThree, delta) => {
    if (shaderRef.current) {
      shaderRef.current.uniforms.uTime.value = stateThree.clock.elapsedTime;

      // Smoothly interpolate morph factor
      const targetFactor = state === TreeState.TREE_SHAPE ? 1.0 : 0.0;
      const currentFactor = shaderRef.current.uniforms.uMorphFactor.value;

      // Linear interpolation with damping
      const speed = 2.0;
      shaderRef.current.uniforms.uMorphFactor.value = THREE.MathUtils.lerp(
        currentFactor,
        targetFactor,
        speed * delta
      );
    }
  });

  return (
    <points>
      <bufferGeometry>
        <bufferAttribute
          attach="attributes-position"
          count={positions.length / 3}
          array={positions} // Initial dummy positions, shader handles mix
          itemSize={3}
        />
        <bufferAttribute
          attach="attributes-aTreePosition"
          count={treePositions.length / 3}
          array={treePositions}
          itemSize={3}
        />
        <bufferAttribute
          attach="attributes-aScatterPosition"
          count={scatterPositions.length / 3}
          array={scatterPositions}
          itemSize={3}
        />
        <bufferAttribute
          attach="attributes-aRandom"
          count={randoms.length}
          array={randoms}
          itemSize={1}
        />
        <bufferAttribute
          attach="attributes-aSize"
          count={sizes.length}
          array={sizes}
          itemSize={1}
        />
      </bufferGeometry>
      <shaderMaterial
        ref={shaderRef}
        args={[FoliageShaderMaterial]}
        transparent
        depthWrite={false}
        blending={THREE.AdditiveBlending}
      />
    </points>
  );
};

import React, { useMemo, useRef, useLayoutEffect } from 'react';
import { useFrame } from '@react-three/fiber';
import * as THREE from 'three';
import { getScatterPoint, randomRange, TREE_HEIGHT, TREE_RADIUS_BOTTOM } from '../utils/math';
import { TreeState, OrnamentData } from '../types';

const tempObj = new THREE.Object3D();
const tempVec3 = new THREE.Vector3();

interface GiftsProps {
  state: TreeState;
}

export const Gifts: React.FC<GiftsProps> = ({ state }) => {
  const meshRef = useRef<THREE.InstancedMesh>(null);
  const count = 40;

  const data = useMemo(() => {
    const d: OrnamentData[] = [];
    const colors = [
      new THREE.Color('#D4AF37'), // Gold
      new THREE.Color('#4B0082'), // Starry Purple
      new THREE.Color('#004225'), // Deep Emerald
      new THREE.Color('#C41E3A'), // Red
    ];

    const bottomY = -TREE_HEIGHT / 2; // -6

    for (let i = 0; i < count; i++) {
      // Scatter Logic (same as ornaments)
      const scatterPos = getScatterPoint(20);

      // Tree Logic (Base Cluster)
      // Radius slightly larger than tree base (5.5 -> ~6 to 7)
      const r = randomRange(2, TREE_RADIUS_BOTTOM + 2);
      const theta = Math.random() * Math.PI * 2;
      const x = r * Math.cos(theta);
      const z = r * Math.sin(theta);
      // Stack slightly on Y
      const y = bottomY + Math.random() * 2; // -6 to -4

      const treePos = new THREE.Vector3(x, y, z);

      d.push({
        type: 'BOX',
        tree: treePos,
        scatter: scatterPos,
        rotation: new THREE.Euler(0, Math.random() * Math.PI * 2, 0),
        scale: randomRange(1.0, 1.5), // Larger than ornaments
        speed: randomRange(0.5, 1.5),
        color: colors[Math.floor(Math.random() * colors.length)]
      });
    }
    return d;
  }, []);

  useLayoutEffect(() => {
    if (meshRef.current) {
      for (let i = 0; i < data.length; i++) {
        meshRef.current.setColorAt(i, data[i].color);
      }
      meshRef.current.instanceColor!.needsUpdate = true;
    }
  }, [data]);

  useFrame((stateThree, delta) => {
    if (!meshRef.current) return;

    // Smooth transition
    const targetMorph = state === TreeState.TREE_SHAPE ? 1 : 0;

    // Store morph value
    if (meshRef.current.userData.morphValue === undefined) meshRef.current.userData.morphValue = 0;
    meshRef.current.userData.morphValue = THREE.MathUtils.lerp(
      meshRef.current.userData.morphValue, 
      targetMorph, 
      1.5 * delta
    );
    const t = meshRef.current.userData.morphValue;
    const time = stateThree.clock.elapsedTime;

    for (let i = 0; i < data.length; i++) {
      const item = data[i];

      // Position
      tempVec3.lerpVectors(item.scatter, item.tree, t);

      // Float when scattered
      if (t < 0.99) {
          tempVec3.y += Math.sin(time * item.speed + i) * 0.2 * (1 - t);
      }

      // Rotation: Spin when scattered, settle when tree
      const rotY = item.rotation.y + (time * 0.5 * (1 - t));

      tempObj.position.copy(tempVec3);
      tempObj.rotation.set(item.rotation.x * (1-t), rotY, item.rotation.z * (1-t));
      tempObj.scale.setScalar(item.scale);

      tempObj.updateMatrix();
      meshRef.current.setMatrixAt(i, tempObj.matrix);
    }
    meshRef.current.instanceMatrix.needsUpdate = true;
  });

  return (
    <instancedMesh ref={meshRef} args={[undefined, undefined, count]}>
      <boxGeometry args={[0.8, 0.8, 0.8]} /> {/* Larger boxes */}
      <meshStandardMaterial 
        metalness={0.5} 
        roughness={0.4}
        envMapIntensity={1.0}
      />
    </instancedMesh>
  );
};

