        depthWrite={false}
        blending={THREE.AdditiveBlending}
      />
    </points>
  );
};

import React, { useMemo, useRef, useLayoutEffect } from 'react';
import { useFrame } from '@react-three/fiber';
import * as THREE from 'three';
import { getScatterPoint, getTreePoint, randomRange } from '../utils/math';
import { TreeState, OrnamentData } from '../types';

const tempObj = new THREE.Object3D();
const tempVec3 = new THREE.Vector3();

interface OrnamentsProps {
  count?: number;
  state: TreeState;
}

export const Ornaments: React.FC<OrnamentsProps> = ({ count = 300, state }) => {
  const meshRef = useRef<THREE.InstancedMesh>(null);
  const purpleRef = useRef<THREE.InstancedMesh>(null);
  const boxesRef = useRef<THREE.InstancedMesh>(null);

  // 1. Standard Sphere Colors: Champagne Gold, Serenity Blue, Platinum
  const sphereColors = useMemo(() => [
    new THREE.Color('#E6D2B5'), // Soft Gold (Champagne)
    new THREE.Color('#A3C1DA'), // Sky Blue (Serenity)
    new THREE.Color('#E5E4E2'), // Platinum
  ], []);

  // 2. New Special Color: Lavender Mist
  const purpleColor = useMemo(() => [
     new THREE.Color('#C5A3CD') // Pastel Purple
  ], []);

  // Separate data generation
  const sphereData = useMemo(() => generateOrnamentData(Math.floor(count * 0.7), 'SPHERE', sphereColors), [count, sphereColors]);
  const purpleData = useMemo(() => generateOrnamentData(Math.floor(count * 0.3), 'SPHERE', purpleColor), [count, purpleColor]);

  // Box Data (Mix of Gold and Blue)
  const boxData = useMemo(() => generateOrnamentData(Math.floor(count / 4), 'BOX', [
      new THREE.Color('#E6D2B5'), 
      new THREE.Color('#A3C1DA')
  ]), [count]);

  useLayoutEffect(() => {
    // Set initial colors
    if (meshRef.current) applyColors(meshRef.current, sphereData);
    if (purpleRef.current) applyColors(purpleRef.current, purpleData);
    if (boxesRef.current) applyColors(boxesRef.current, boxData);
  }, [sphereData, purpleData, boxData]);

  useFrame((rootState, delta) => {
    const time = rootState.clock.elapsedTime;
    const targetMorph = state === TreeState.TREE_SHAPE ? 1 : 0;

    // Update Standard Spheres
    updateInstances(meshRef.current, sphereData, targetMorph, time, delta);

    // Update Purple Spheres
    updateInstances(purpleRef.current, purpleData, targetMorph, time, delta);

    // Update Boxes
    updateInstances(boxesRef.current, boxData, targetMorph, time, delta);
  });

  return (
    <group>
      {/* 1. Standard Spheres: Glossy Pastel */}
      <instancedMesh ref={meshRef} args={[undefined, undefined, sphereData.length]}>
        <sphereGeometry args={[0.25, 32, 32]} />
        <meshStandardMaterial 
          metalness={0.8} 
          roughness={0.2} 
          envMapIntensity={2}
        />
      </instancedMesh>

      {/* 2. Special Purple Spheres: Matte Pastel */}
      <instancedMesh ref={purpleRef} args={[undefined, undefined, purpleData.length]}>
        <sphereGeometry args={[0.25, 32, 32]} />
        {/* Soft matte look for the lavender */}
        <meshPhysicalMaterial 
          metalness={0.4} 
          roughness={0.5} 
          envMapIntensity={1.2}
          clearcoat={0.1}
        />
      </instancedMesh>

      {/* 3. Boxes: Gifts */}
      <instancedMesh ref={boxesRef} args={[undefined, undefined, boxData.length]}>
        <boxGeometry args={[0.4, 0.4, 0.4]} />
        <meshStandardMaterial 
          metalness={0.5} 
          roughness={0.3}
          envMapIntensity={1.5}
        />
      </instancedMesh>
    </group>
  );
};

// --- Helpers ---

function generateOrnamentData(count: number, type: 'SPHERE' | 'BOX', colorPalette: THREE.Color[]): OrnamentData[] {
  const data: OrnamentData[] = [];

  for (let i = 0; i < count; i++) {
    const treePos = getTreePoint(12, 5.0, -6);
    // Push ornaments slightly outward so they sit ON the leaves, not inside
    const radialDir = new THREE.Vector3(treePos.x, 0, treePos.z).normalize();
    treePos.add(radialDir.multiplyScalar(0.4)); 

    const scatterPos = getScatterPoint(20);

    data.push({
      type,
      tree: treePos,
      scatter: scatterPos,
      rotation: new THREE.Euler(Math.random() * Math.PI, Math.random() * Math.PI, 0),
      scale: randomRange(0.8, 1.5),
      speed: randomRange(0.5, 2.0),
      color: colorPalette[Math.floor(Math.random() * colorPalette.length)]
    });
  }
  return data;
}

function applyColors(mesh: THREE.InstancedMesh, data: OrnamentData[]) {
  for (let i = 0; i < data.length; i++) {
    mesh.setColorAt(i, data[i].color);
  }
  mesh.instanceColor!.needsUpdate = true;
}

function updateInstances(
  mesh: THREE.InstancedMesh | null, 
  data: OrnamentData[], 
  targetMorph: number, 
  time: number,
  delta: number
) {
  if (!mesh) return;

  if (mesh.userData.morphValue === undefined) mesh.userData.morphValue = 0;

  const speed = 1.5;
  mesh.userData.morphValue = THREE.MathUtils.lerp(mesh.userData.morphValue, targetMorph, speed * delta);
  const t = mesh.userData.morphValue;

  for (let i = 0; i < data.length; i++) {
    const item = data[i];

    // Position Mix
    tempVec3.lerpVectors(item.scatter, item.tree, t);

    // Add noise/floating
    const floatAmp = (1 - t) * 0.5; // Floats more when scattered
    tempVec3.y += Math.sin(time * item.speed + i) * floatAmp;
    tempVec3.x += Math.cos(time * item.speed * 0.5 + i) * floatAmp;

    // Rotation
    // Spin when scattered, stabilize when tree
    const rotX = item.rotation.x + (time * 0.2 * (1 - t));
    const rotY = item.rotation.y + (time * 0.5 * (1 - t));

    tempObj.position.copy(tempVec3);
    tempObj.rotation.set(rotX, rotY, item.rotation.z);
    tempObj.scale.setScalar(item.scale * (t * 0.5 + 0.5)); // Grow slightly when forming tree

    tempObj.updateMatrix();
    mesh.setMatrixAt(i, tempObj.matrix);
  }
  mesh.instanceMatrix.needsUpdate = true;
}

import React, { useMemo, useRef, useLayoutEffect } from 'react';
import { useFrame } from '@react-three/fiber';
import * as THREE from 'three';
import { getScatterPoint, randomRange, TREE_HEIGHT, TREE_RADIUS_BOTTOM } from '../utils/math';
import { TreeState, OrnamentData } from '../types';

const tempObj = new THREE.Object3D();
const tempVec3 = new THREE.Vector3();

interface GiftsProps {
  state: TreeState;
}

export const Gifts: React.FC<GiftsProps> = ({ state }) => {
  const meshRef = useRef<THREE.InstancedMesh>(null);
  const count = 40;

  const data = useMemo(() => {
    const d: OrnamentData[] = [];
    // Pastel Palette for Base Gifts
    const colors = [
      new THREE.Color('#E6D2B5'), // Soft Gold
      new THREE.Color('#C5A3CD'), // Lavender
      new THREE.Color('#2F4F4F'), // Desaturated Teal
      new THREE.Color('#A3C1DA'), // Serenity Blue
    ];

    const bottomY = -TREE_HEIGHT / 2; // -6

    for (let i = 0; i < count; i++) {
      // Scatter Logic (same as ornaments)
      const scatterPos = getScatterPoint(20);

      // Tree Logic (Base Cluster)
      const r = randomRange(2, TREE_RADIUS_BOTTOM + 2);
      const theta = Math.random() * Math.PI * 2;
      const x = r * Math.cos(theta);
      const z = r * Math.sin(theta);
      const y = bottomY + Math.random() * 2; // -6 to -4

      const treePos = new THREE.Vector3(x, y, z);

      d.push({
        type: 'BOX',
        tree: treePos,
        scatter: scatterPos,
        rotation: new THREE.Euler(0, Math.random() * Math.PI * 2, 0),
        scale: randomRange(1.0, 1.5), 
        speed: randomRange(0.5, 1.5),
        color: colors[Math.floor(Math.random() * colors.length)]
      });
    }
    return d;
  }, []);

  useLayoutEffect(() => {
    if (meshRef.current) {
      for (let i = 0; i < data.length; i++) {
        meshRef.current.setColorAt(i, data[i].color);
      }
      meshRef.current.instanceColor!.needsUpdate = true;
    }
  }, [data]);

  useFrame((stateThree, delta) => {
    if (!meshRef.current) return;

    // Smooth transition
    const targetMorph = state === TreeState.TREE_SHAPE ? 1 : 0;

    if (meshRef.current.userData.morphValue === undefined) meshRef.current.userData.morphValue = 0;
    meshRef.current.userData.morphValue = THREE.MathUtils.lerp(
      meshRef.current.userData.morphValue, 
      targetMorph, 
      1.5 * delta
    );
    const t = meshRef.current.userData.morphValue;
    const time = stateThree.clock.elapsedTime;

    for (let i = 0; i < data.length; i++) {
      const item = data[i];

      // Position
      tempVec3.lerpVectors(item.scatter, item.tree, t);

      // Float when scattered
      if (t < 0.99) {
          tempVec3.y += Math.sin(time * item.speed + i) * 0.2 * (1 - t);
      }

      const rotY = item.rotation.y + (time * 0.5 * (1 - t));

      tempObj.position.copy(tempVec3);
      tempObj.rotation.set(item.rotation.x * (1-t), rotY, item.rotation.z * (1-t));
      tempObj.scale.setScalar(item.scale);

      tempObj.updateMatrix();
      meshRef.current.setMatrixAt(i, tempObj.matrix);
    }
    meshRef.current.instanceMatrix.needsUpdate = true;
  });

  return (
    <instancedMesh ref={meshRef} args={[undefined, undefined, count]}>
      <boxGeometry args={[0.8, 0.8, 0.8]} /> 
      <meshStandardMaterial 
        metalness={0.5} 
        roughness={0.4}
        envMapIntensity={1.0}
      />
    </instancedMesh>
  );
};

