        angle={0.5} 
        penumbra={1} 
        intensity={2} 
        color="#E6D2B5" 
        castShadow 
      />
      <pointLight position={[-10, 5, -10]} intensity={1.5} color="#E6D2B5" />
      <pointLight position={[0, -5, 10]} intensity={0.5} color="#C5A3CD" />

      {/* Fix A: Dedicated Base Light for Gifts */}
      <pointLight 
        position={[0, -12, 0]} 
        intensity={5.0} 
        distance={25} 
        color="#FFD1A3" // Warm White
        decay={2}
      />

      {/* Environment for reflections */}
      <Environment preset="city" />

      {/* Background Ambience */}
      <Stars radius={100} depth={50} count={5000} factor={4} saturation={0} fade speed={1} />

      <group ref={groupRef} position={[0, -4, 0]}>
