import React, { useMemo, useRef, useEffect } from 'react';
import { useFrame, useLoader, useThree } from '@react-three/fiber';
import * as THREE from 'three';
import { getScatterPoint, getTreePoint, randomRange } from '../utils/math';
import { TreeState, UserPhotoData } from '../types';

interface UserPhotosProps {
  photos: string[];
  state: TreeState;
  focusedId: string | null;
}

// Sub-component for individual photo to handle texture loading gracefully
const PhotoFrame: React.FC<{ data: UserPhotoData; state: TreeState; isFocused: boolean }> = ({ data, state, isFocused }) => {
  const groupRef = useRef<THREE.Group>(null);
  const texture = useLoader(THREE.TextureLoader, data.url);
  const { gl } = useThree();

  // Fix Texture Flickering / Aliasing
  useEffect(() => {
    if (texture) {
      texture.generateMipmaps = true;
      texture.minFilter = THREE.LinearMipmapLinearFilter; 
      texture.magFilter = THREE.LinearFilter;
      texture.anisotropy = gl.capabilities.getMaxAnisotropy(); 
      texture.needsUpdate = true;
    }
  }, [texture, gl]);

  // Track the morph transition value (0 to 1)
  const morphRef = useRef(0);

  useFrame((rootState, delta) => {
    if (!groupRef.current) return;

    const time = rootState.clock.elapsedTime;

    // --- STATE MACHINE ANIMATION LOGIC ---

    // Determine Target Position, Rotation, Scale based on Mode
    let targetPos = new THREE.Vector3();
    let targetRot = new THREE.Euler();
    let targetScale = 1.0;

    if (state === TreeState.FOCUS && isFocused) {
        // MODE C: FOCUS (Foreground)
        // Adjust for Camera Position (0, 2, 25) and Group Position (0, -4, 0).
        // To be centered on screen (World Y ~= 2), we need Local Y = 2 - (-4) = 6.
        // To be in front of camera (World Z ~= 18), we need Local Z = 18.
        targetPos.set(0, 6, 18);
        targetRot.set(0, 0, 0); // Face camera directly (assuming Group Rotation is reset to 0)
        targetScale = 5.0;      // Scale up 5x
    } else if (state === TreeState.TREE_SHAPE) {
        // MODE A: TREE
        targetPos.copy(data.tree);
        targetRot.copy(data.rotation);
        targetScale = data.scale;
    } else {
        // MODE B: SCATTER (Background for non-focused items in FOCUS mode)
        targetPos.copy(data.scatter);

        // Add floating noise for SCATTER mode
        targetPos.y += Math.sin(time * data.speed) * 0.5;
        targetPos.x += Math.cos(time * data.speed * 0.5) * 0.5;

        // Spin rotation
        targetRot.set(
            data.rotation.x + (time * 0.2),
            data.rotation.y + (time * 0.3),
            data.rotation.z
        );
        targetScale = data.scale;
    }

    // --- LERP TRANSITIONS ---
    // Smoothly interpolate current transform to target using 0.05 factor
    const lerpFactor = 0.05;

    groupRef.current.position.lerp(targetPos, lerpFactor);

    // Lerp Rotation (Euler lerp requires converting to Quaternion or manual)
    // Simple manual lerp for Euler is sufficient here for visual effect
    groupRef.current.rotation.x = THREE.MathUtils.lerp(groupRef.current.rotation.x, targetRot.x, lerpFactor);
    groupRef.current.rotation.y = THREE.MathUtils.lerp(groupRef.current.rotation.y, targetRot.y, lerpFactor);
    groupRef.current.rotation.z = THREE.MathUtils.lerp(groupRef.current.rotation.z, targetRot.z, lerpFactor);

    groupRef.current.scale.lerp(new THREE.Vector3(targetScale, targetScale, targetScale), lerpFactor);
  });

  return (
    <group ref={groupRef}>
      {/* Gold Frame */}
      <mesh position={[0, 0, -0.06]}>
        <boxGeometry args={[1.2, 1.2, 0.1]} />
        <meshStandardMaterial 
            color="#D4AF37" 
            metalness={0.8} 
            roughness={0.2} 
            envMapIntensity={2} 
        />
      </mesh>

      {/* The Photo */}
      <mesh position={[0, 0, 0]}>
        <planeGeometry args={[1, 1]} />
        <meshBasicMaterial map={texture} side={THREE.DoubleSide} />
      </mesh>
    </group>
  );
};

export const UserPhotos: React.FC<UserPhotosProps> = ({ photos, state, focusedId }) => {
  // Generate 3D data for photos only when the photo list changes
  const photosData = useMemo(() => {
    return photos.map((url, index) => {
      // Position photos in the middle-to-bottom section of the tree for better visibility
      const treePos = getTreePoint(10, 5, -5); 
      const radialDir = new THREE.Vector3(treePos.x, 0, treePos.z).normalize();
      treePos.add(radialDir.multiplyScalar(0.8));

      return {
        id: `photo-${index}`,
        url,
        tree: treePos,
        scatter: getScatterPoint(18),
        rotation: new THREE.Euler(0, Math.random() * Math.PI * 2, 0), 
        scale: randomRange(0.8, 1.2),
        speed: randomRange(0.5, 1.5),
      } as UserPhotoData;
    });
  }, [photos]);

  return (
    <group>
      {photosData.map((data) => (
        <PhotoFrame 
            key={data.id} 
            data={data} 
            state={state} 
            isFocused={focusedId === data.id}
        />
      ))}
    </group>
  );
};

import React, { useRef, useMemo, useEffect } from 'react';
import { useFrame, useThree } from '@react-three/fiber';
import { OrbitControls, Environment, PerspectiveCamera, Stars } from '@react-three/drei';
import { EffectComposer, Bloom, Vignette, Noise } from '@react-three/postprocessing';
import * as THREE from 'three';
import { FilesetResolver, HandLandmarker } from '@mediapipe/tasks-vision';
import { Foliage } from './Foliage';
import { Ornaments } from './Ornaments';
import { UserPhotos } from './UserPhotos';
import { Gifts } from './Gifts';
import { TreeState } from '../types';

// --- Base Sparkles (Fireflies) ---
const BaseSparkles = () => {
  const count = 200;
  const mesh = useRef<THREE.Points>(null);

  const { positions, randoms } = useMemo(() => {
    const pos = new Float32Array(count * 3);
    const rnd = new Float32Array(count);

    for (let i = 0; i < count; i++) {
        // Radius 10 to 20
        const r = 10 + Math.random() * 10; 
        const theta = Math.random() * Math.PI * 2;

        pos[i * 3] = r * Math.cos(theta); // x
        pos[i * 3 + 1] = -15 + Math.random() * 7; // y: -15 to -8
        pos[i * 3 + 2] = r * Math.sin(theta); // z

        rnd[i] = Math.random();
    }
    return { positions: pos, randoms: rnd };
  }, []);

  useFrame((state) => {
      if(mesh.current) {
          const time = state.clock.elapsedTime;
          // Gentle floating movement
          mesh.current.position.y = Math.sin(time * 0.2) * 0.5;
          mesh.current.rotation.y = time * 0.05;
      }
  });

  return (
      <points ref={mesh}>
          <bufferGeometry>
              <bufferAttribute attach="attributes-position" count={count} array={positions} itemSize={3} />
          </bufferGeometry>
          <pointsMaterial 
            size={0.15} 
            color="#FFEA00" 
            transparent 
            opacity={0.6} 
            blending={THREE.AdditiveBlending} 
            depthWrite={false}
          />
      </points>
  );
};

interface ExperienceProps {
  treeState: TreeState;
  setTreeState: (state: TreeState) => void;
  userPhotos: string[];
  focusedPhotoId: string | null;
  setFocusedPhotoId: (id: string | null) => void;
}

export const Experience: React.FC<ExperienceProps> = ({ 
  treeState, 
  setTreeState, 
  userPhotos,
  focusedPhotoId,
  setFocusedPhotoId
}) => {
  const cameraRef = useRef<THREE.PerspectiveCamera>(null);
  const groupRef = useRef<THREE.Group>(null);
  const starRef = useRef<THREE.Mesh>(null);

  // Hand Tracking Refs
  const videoRef = useRef<HTMLVideoElement | null>(null);
  const handLandmarkerRef = useRef<HandLandmarker | null>(null);
  const lastVideoTimeRef = useRef(-1);
  const targetRotation = useRef({ x: 0, y: 0 });

  // Setup MediaPipe
  useEffect(() => {
    let isMounted = true;

    const setupHandTracking = async () => {
      try {
        const vision = await FilesetResolver.forVisionTasks(
          "https://cdn.jsdelivr.net/npm/@mediapipe/tasks-vision@0.10.8/wasm"
        );

        if (!isMounted) return;

        const landmarker = await HandLandmarker.createFromOptions(vision, {
          baseOptions: {
            modelAssetPath: `https://storage.googleapis.com/mediapipe-models/hand_landmarker/hand_landmarker/float16/1/hand_landmarker.task`,
            delegate: "GPU"
          },
          runningMode: "VIDEO",
          numHands: 1
        });

        if (!isMounted) {
            landmarker.close();
            return;
        }

        handLandmarkerRef.current = landmarker;

        // Get Webcam
        const video = document.getElementById("webcam") as HTMLVideoElement;
        videoRef.current = video;

        if (navigator.mediaDevices && navigator.mediaDevices.getUserMedia) {
          const stream = await navigator.mediaDevices.getUserMedia({ 
            video: { 
              width: 1280, 
              height: 720 
            } 
          });

          if (!isMounted) {
            stream.getTracks().forEach(t => t.stop());
            return;
          }

          video.srcObject = stream;
          video.onloadedmetadata = () => {
            if (isMounted) video.play().catch(e => console.error("Video play error:", e));
          };
        }
      } catch (error) {
        console.error("Error initializing MediaPipe or Webcam:", error);
      }
    };

    setupHandTracking();

    // Cleanup function to handle Strict Mode unmounts
    return () => {
      isMounted = false;

      // Close Landmarker
      if (handLandmarkerRef.current) {
        handLandmarkerRef.current.close();
        handLandmarkerRef.current = null;
      }

      // Stop Camera Stream
      const video = document.getElementById("webcam") as HTMLVideoElement;
      if (video && video.srcObject) {
        const stream = video.srcObject as MediaStream;
        stream.getTracks().forEach(track => track.stop());
        video.srcObject = null;
      }
    };
  }, []);

  // Gesture Recognition Logic
  const detectGestures = (landmarks: any[]) => {
    const wrist = landmarks[0];
    const thumbTip = landmarks[4];
    const indexTip = landmarks[8];
    const midTip = landmarks[12];
    const ringTip = landmarks[16];
    const pinkyTip = landmarks[20];
    const handCenter = landmarks[9]; // Middle finger mcp

    // Distance Helper
    const dist = (p1: any, p2: any) => Math.sqrt(
      Math.pow(p1.x - p2.x, 2) + Math.pow(p1.y - p2.y, 2) + Math.pow(p1.z - p2.z, 2)
    );

    // 1. FIST Detection (Average distance from tips to wrist < 0.15)
    const tips = [indexTip, midTip, ringTip, pinkyTip];
    const avgDistToWrist = tips.reduce((acc, tip) => acc + dist(tip, wrist), 0) / 4;

    // 2. OPEN HAND Detection (Avg distance > 0.35)
    // 3. PINCH Detection (Thumb to Index < 0.05)
    const pinchDist = dist(thumbTip, indexTip);

    // --- State Machine Logic ---
    if (avgDistToWrist < 0.15) {
      if (treeState !== TreeState.TREE_SHAPE) setTreeState(TreeState.TREE_SHAPE);
    } 
    else if (avgDistToWrist > 0.35) {
      if (treeState !== TreeState.SCATTERED) setTreeState(TreeState.SCATTERED);
    }
    else if (pinchDist < 0.05) {
      if (treeState !== TreeState.FOCUS && userPhotos.length > 0) {
        setTreeState(TreeState.FOCUS);
        // Randomly select a photo
        const randomId = `photo-${Math.floor(Math.random() * userPhotos.length)}`;
        setFocusedPhotoId(randomId);
      }
    }

    // 4. HAND ROTATION (Active in SCATTER)
    // We only update target rotation if NOT in TREE_SHAPE, but usually only helpful in SCATTER
    if (treeState !== TreeState.TREE_SHAPE) {
       // Map X (0-1) to Rotation Y (-1.5 to 1.5 radians approx)
       // Map Y (0-1) to Rotation X
       // In MediaPipe, X is 0 (left) to 1 (right)
       targetRotation.current.y = (handCenter.x - 0.5) * 3.0; 
       targetRotation.current.x = (handCenter.y - 0.5) * 3.0; 
    } else {
        targetRotation.current.x = 0;
        targetRotation.current.y = 0; // Reset or let auto-spin handle it
    }
  };

  // Mouse Interaction Handler
  const handlePhotoClick = (id: string) => {
    setFocusedPhotoId(id);
    setTreeState(TreeState.FOCUS);
  };

  useFrame((state) => {
    // Process MediaPipe Frame with Strict Validation
    if (
      handLandmarkerRef.current && 
      videoRef.current && 
      videoRef.current.readyState >= 2 && // HAVE_CURRENT_DATA
      !videoRef.current.paused &&         // Video must be playing
      videoRef.current.videoWidth > 0 &&  // Strictly positive width
      videoRef.current.videoHeight > 0 && // Strictly positive height
      videoRef.current.currentTime !== lastVideoTimeRef.current
    ) {
        lastVideoTimeRef.current = videoRef.current.currentTime;
        try {
          const results = handLandmarkerRef.current.detectForVideo(videoRef.current, performance.now());

          if (results.landmarks && results.landmarks.length > 0) {
              detectGestures(results.landmarks[0]);
          }
        } catch (e) {
          // Swallow sporadic errors or graph crashes to prevent app freeze
          // console.warn("MediaPipe Detect Error:", e);
        }
    }

    // Animation Loop for Group Rotation
    if (groupRef.current) {
        if (treeState === TreeState.TREE_SHAPE) {
            // Default Auto Spin
            groupRef.current.rotation.y += 0.002;
            // Lerp back to 0 on X
            groupRef.current.rotation.x = THREE.MathUtils.lerp(groupRef.current.rotation.x, 0, 0.05);
        } else if (treeState === TreeState.FOCUS) {
            // MODE: FOCUS - Center the Group
            // Smoothly reset rotation to 0,0,0 so the coordinate system aligns with Camera
            groupRef.current.rotation.x = THREE.MathUtils.lerp(groupRef.current.rotation.x, 0, 0.1);
            groupRef.current.rotation.y = THREE.MathUtils.lerp(groupRef.current.rotation.y, 0, 0.1);
        } else {
            // MODE: SCATTER - Hand Controlled Rotation
            groupRef.current.rotation.y = THREE.MathUtils.lerp(groupRef.current.rotation.y, targetRotation.current.y, 0.05);
            groupRef.current.rotation.x = THREE.MathUtils.lerp(groupRef.current.rotation.x, targetRotation.current.x, 0.05);
        }
    }

    // Star Spin
    if (starRef.current) {
        starRef.current.rotation.y += 0.01;
    }
  });

  // Generate 5-pointed Star Shape
  const starShape = useMemo(() => {
    const shape = new THREE.Shape();
    const outerRadius = 1.5;
    const innerRadius = 0.7; // Depth of the star cuts
    const points = 5;

    for (let i = 0; i < points * 2; i++) {
      const angle = (i * Math.PI) / points;
      const radius = i % 2 === 0 ? outerRadius : innerRadius;
      const x = Math.cos(angle) * radius;
      const y = Math.sin(angle) * radius;
      if (i === 0) shape.moveTo(x, y);
      else shape.lineTo(x, y);
    }
    shape.closePath();
    return shape;
  }, []);

  const starExtrudeSettings = useMemo(() => ({
    depth: 0.5,
    bevelEnabled: true,
    bevelThickness: 0.1,
    bevelSize: 0.1,
    bevelSegments: 2
  }), []);

  return (
    <>
      <PerspectiveCamera makeDefault position={[0, 2, 25]} fov={50} ref={cameraRef} />

      <OrbitControls 
        enablePan={false} 
        minPolarAngle={Math.PI / 3} 
        maxPolarAngle={Math.PI / 1.8}
        minDistance={10}
        maxDistance={40}
      />

      {/* Lighting: Bright & Cheerful */}
      <ambientLight intensity={0.6} color="#ffffff" /> 
      <spotLight 
        position={[10, 20, 10]} 
        angle={0.5} 
        penumbra={1} 
        intensity={2} 
        color="#fff" 
        castShadow 
      />
      <pointLight position={[-10, 5, -10]} intensity={1.5} color="#FFEA00" />
      <pointLight position={[0, -5, 10]} intensity={0.5} color="#00BFFF" />

      <pointLight 
        position={[0, -12, 0]} 
        intensity={4.0} 
        distance={25} 
        color="#FFD700" 
        decay={2}
      />

      <Environment preset="city" />
      <Stars radius={100} depth={50} count={5000} factor={4} saturation={0} fade speed={1} />

      <group ref={groupRef} position={[0, -4, 0]}>
        <BaseSparkles />
        <pointLight position={[0, 6, 0]} intensity={1} color="#FFD700" distance={10} decay={2} />

        <Foliage state={treeState} count={12000} />
        <Ornaments state={treeState} count={600} />
        <Gifts state={treeState} />

        {/* Pass click handler and props */}
        <UserPhotos 
            photos={userPhotos} 
            state={treeState} 
            focusedId={focusedPhotoId}
            onPhotoClick={handlePhotoClick}
        />

        <group position={[0, 6.5, 0]}>
            <mesh 
                ref={starRef} 
                scale={treeState === TreeState.TREE_SHAPE ? 1 : 0}
                rotation={[0, 0, Math.PI / 10]} 
            >
                <extrudeGeometry args={[starShape, starExtrudeSettings]} />
                <meshStandardMaterial 
                    color="#FFD700" 
                    emissive="#FFD700" 
                    emissiveIntensity={2.0} 
                    toneMapped={false}
                />
                <pointLight color="#FFD700" distance={30} intensity={5} decay={2} />
            </mesh>
        </group>
      </group>

      <EffectComposer disableNormalPass>
        <Bloom 
          luminanceThreshold={0.8} 
          mipmapBlur 
          intensity={1.2} 
          radius={0.5} 
        />
        <Vignette eskil={false} offset={0.1} darkness={1.0} />
        <Noise opacity={0.02} /> 
      </EffectComposer>
    </>
  );
};

import React, { useMemo, useRef, useEffect } from 'react';
import { useFrame, useLoader, useThree } from '@react-three/fiber';
import * as THREE from 'three';
import { getScatterPoint, getTreePoint, randomRange } from '../utils/math';
import { TreeState, UserPhotoData } from '../types';

interface UserPhotosProps {
  photos: string[];
  state: TreeState;
  focusedId: string | null;
  onPhotoClick: (id: string) => void;
}

// Sub-component for individual photo to handle texture loading gracefully
const PhotoFrame: React.FC<{ 
  data: UserPhotoData; 
  state: TreeState; 
  isFocused: boolean;
  onPhotoClick: (id: string) => void; 
}> = ({ data, state, isFocused, onPhotoClick }) => {
  const groupRef = useRef<THREE.Group>(null);
  const texture = useLoader(THREE.TextureLoader, data.url);
  const { gl } = useThree();

  // Dynamic Aspect Ratio Logic
  const { width, height } = texture.image;
  const aspect = width / height;
  const baseHeight = 2.0; // Base height standard
  const planeWidth = baseHeight * aspect;
  const framePadding = 0.4;
  const frameWidth = planeWidth + framePadding;
  const frameHeight = baseHeight + framePadding;

  // Fix Texture Flickering / Aliasing
  useEffect(() => {
    if (texture) {
      texture.generateMipmaps = true;
      texture.minFilter = THREE.LinearMipmapLinearFilter; 
      texture.magFilter = THREE.LinearFilter;
      texture.anisotropy = gl.capabilities.getMaxAnisotropy(); 
      texture.needsUpdate = true;
    }
  }, [texture, gl]);

  useFrame((rootState, delta) => {
    if (!groupRef.current) return;

    const time = rootState.clock.elapsedTime;

    // --- STATE MACHINE ANIMATION LOGIC ---

    // Determine Target Position, Rotation, Scale based on Mode
    let targetPos = new THREE.Vector3();
    let targetRot = new THREE.Euler();
    let targetScale = 1.0;

    if (state === TreeState.FOCUS && isFocused) {
        // MODE C: FOCUS (Foreground)
        // Adjust for Camera Position (0, 2, 25) and Group Position (0, -4, 0).
        // To be centered on screen (World Y ~= 2), we need Local Y = 2 - (-4) = 6.
        // To be in front of camera (World Z ~= 18), we need Local Z = 18.
        targetPos.set(0, 6, 18);

        // ORIENTATION FIX:
        // Ensure photo is perfectly flat facing the camera.
        // Since the main Group rotation is reset to (0,0,0) in Experience.tsx,
        // we set local rotation to (0,0,0) here.
        targetRot.set(0, 0, 0); 

        // Dynamic scaling: Don't scale up too huge if the base geometry is already size 2.0
        // Scale 2.5x gives ~5 unit height, good for visibility
        targetScale = 2.5; 
    } else if (state === TreeState.TREE_SHAPE) {
        // MODE A: TREE
        targetPos.copy(data.tree);
        targetRot.copy(data.rotation);
        targetScale = data.scale;
    } else {
        // MODE B: SCATTER (Background for non-focused items in FOCUS mode)
        targetPos.copy(data.scatter);

        // Add floating noise for SCATTER mode
        targetPos.y += Math.sin(time * data.speed) * 0.5;
        targetPos.x += Math.cos(time * data.speed * 0.5) * 0.5;

        // Spin rotation
        targetRot.set(
            data.rotation.x + (time * 0.2),
            data.rotation.y + (time * 0.3),
            data.rotation.z
        );
        targetScale = data.scale;
    }

    // --- LERP TRANSITIONS ---
    // Smoothly interpolate current transform to target using 0.05 factor
    const lerpFactor = 0.05;

    groupRef.current.position.lerp(targetPos, lerpFactor);

    // Lerp Rotation
    groupRef.current.rotation.x = THREE.MathUtils.lerp(groupRef.current.rotation.x, targetRot.x, lerpFactor);
    groupRef.current.rotation.y = THREE.MathUtils.lerp(groupRef.current.rotation.y, targetRot.y, lerpFactor);
    groupRef.current.rotation.z = THREE.MathUtils.lerp(groupRef.current.rotation.z, targetRot.z, lerpFactor);

    groupRef.current.scale.lerp(new THREE.Vector3(targetScale, targetScale, targetScale), lerpFactor);
  });

  return (
    <group 
      ref={groupRef}
      onClick={(e) => {
        e.stopPropagation(); // Stop raycast bubbling
        onPhotoClick(data.id);
      }}
      onPointerOver={() => document.body.style.cursor = 'pointer'}
      onPointerOut={() => document.body.style.cursor = 'auto'}
    >
      {/* Gold Frame - Dynamic Size */}
      <mesh position={[0, 0, -0.06]}>
        <boxGeometry args={[frameWidth, frameHeight, 0.2]} />
        <meshStandardMaterial 
            color="#D4AF37" 
            metalness={0.8} 
            roughness={0.2} 
            envMapIntensity={2} 
        />
      </mesh>

      {/* The Photo - Dynamic Size */}
      <mesh position={[0, 0, 0]}>
        <planeGeometry args={[planeWidth, baseHeight]} />
        <meshBasicMaterial map={texture} side={THREE.DoubleSide} />
      </mesh>
    </group>
  );
};

export const UserPhotos: React.FC<UserPhotosProps> = ({ photos, state, focusedId, onPhotoClick }) => {
  // Generate 3D data for photos only when the photo list changes
  const photosData = useMemo(() => {
    return photos.map((url, index) => {
