      texture.minFilter = THREE.LinearMipmapLinearFilter; 
      texture.magFilter = THREE.LinearFilter;
      texture.anisotropy = gl.capabilities.getMaxAnisotropy(); 
      texture.needsUpdate = true;
    }
  }, [texture, gl]);

  useFrame((rootState, delta) => {
    if (!groupRef.current) return;

    const time = rootState.clock.elapsedTime;

    // --- STATE MACHINE ANIMATION LOGIC ---

    // We use Quaternions for rotation now to support smooth camera tracking (HUD mode)
    let targetPos = new THREE.Vector3();
    let targetRot = new THREE.Quaternion();
    let targetScale = 1.0;

    if (state === TreeState.FOCUS && isFocused) {
        // MODE C: FOCUS (HUD / Head-Locked)
        // The photo continuously tracks the camera to stay perfectly centered (Billboard).

        // 1. Calculate World Target Position
        // Place it 15 units in front of the camera (in world space)
        const distance = 15.0; 
        const forward = new THREE.Vector3();
        camera.getWorldDirection(forward);
        const targetWorldPos = camera.position.clone().add(forward.multiplyScalar(distance));

        // 2. Convert to Local Space
        // Since this group is a child of the rotating main tree group, 
        // we must convert the static world "HUD" coordinate into the parent's local space.
        if (groupRef.current.parent) {
            targetPos.copy(targetWorldPos);
            groupRef.current.parent.worldToLocal(targetPos);

            // 3. Orientation Calculation
            // We want the object's WORLD rotation to match the Camera's WORLD rotation.
            // Equation: ParentWorldQuat * LocalQuat = CameraWorldQuat
            // Solution: LocalQuat = inverse(ParentWorldQuat) * CameraWorldQuat

            const parentWorldQuat = new THREE.Quaternion();
            groupRef.current.parent.getWorldQuaternion(parentWorldQuat);

            targetRot.copy(camera.quaternion);
            targetRot.premultiply(parentWorldQuat.invert());
        } else {
            // Fallback (should not happen in this hierarchy)
            targetPos.copy(targetWorldPos);
            targetRot.copy(camera.quaternion);
        }

        // 4. Scale
        targetScale = 2.0; 

    } else if (state === TreeState.TREE_SHAPE) {
        // MODE A: TREE
        targetPos.copy(data.tree);

        // Convert stored Euler to Quaternion
        const euler = new THREE.Euler(data.rotation.x, data.rotation.y, data.rotation.z);
        targetRot.setFromEuler(euler);

        targetScale = data.scale;
    } else {
        // MODE B: SCATTER (Background)
        targetPos.copy(data.scatter);

        // Add floating noise for SCATTER mode
        targetPos.y += Math.sin(time * data.speed) * 0.5;
        targetPos.x += Math.cos(time * data.speed * 0.5) * 0.5;

        // Spin rotation (Animated Euler -> Quaternion)
        const euler = new THREE.Euler(
            data.rotation.x + (time * 0.2),
            data.rotation.y + (time * 0.3),
            data.rotation.z
        );
        targetRot.setFromEuler(euler);

        targetScale = data.scale;
    }

    // --- LERP TRANSITIONS ---
    // Use a factor of 0.1 for responsive but smooth tracking
    const lerpFactor = 0.1;

    groupRef.current.position.lerp(targetPos, lerpFactor);
    groupRef.current.quaternion.slerp(targetRot, lerpFactor);
    groupRef.current.scale.lerp(new THREE.Vector3(targetScale, targetScale, targetScale), lerpFactor);
  });

  return (
    <group 
      ref={groupRef}
      onClick={(e) => {
        e.stopPropagation(); // Stop raycast bubbling
        onPhotoClick(data.id);
      }}
      onPointerOver={() => document.body.style.cursor = 'pointer'}
      onPointerOut={() => document.body.style.cursor = 'auto'}
    >
      {/* Gold Frame - Dynamic Size */}
      {/* Centered at 0. Depth 0.2 means faces are at -0.1 and +0.1 */}
      <mesh position={[0, 0, 0]}>
        <boxGeometry args={[frameWidth, frameHeight, 0.2]} />
        <meshStandardMaterial 
            color="#D4AF37" 
            metalness={0.8} 
            roughness={0.2} 
            envMapIntensity={2} 
        />
      </mesh>

      {/* The Photo - Dynamic Size */}
      {/* Placed at +0.15 to strictly prevent Z-fighting with the frame's +0.1 face */}
      <mesh position={[0, 0, 0.15]}>
        <planeGeometry args={[planeWidth, baseHeight]} />
        <meshBasicMaterial map={texture} side={THREE.DoubleSide} />
      </mesh>
    </group>
  );
};

export const UserPhotos: React.FC<UserPhotosProps> = ({ photos, state, focusedId, onPhotoClick }) => {
  // Generate 3D data for photos only when the photo list changes
  const photosData = useMemo(() => {
    return photos.map((url, index) => {
      // Position photos in the middle-to-bottom section of the tree for better visibility
      const treePos = getTreePoint(10, 5, -5); 
      const radialDir = new THREE.Vector3(treePos.x, 0, treePos.z).normalize();
      treePos.add(radialDir.multiplyScalar(0.8));

      return {
        id: `photo-${index}`,
        url,
        tree: treePos,
        scatter: getScatterPoint(18),
        rotation: new THREE.Euler(0, Math.random() * Math.PI * 2, 0), 
        scale: randomRange(0.8, 1.2),
        speed: randomRange(0.5, 1.5),
      } as UserPhotoData;
    });
  }, [photos]);

  return (
    <group>
      {photosData.map((data) => (
        <PhotoFrame 
            key={data.id} 
            data={data} 
            state={state} 
            isFocused={focusedId === data.id}
            onPhotoClick={onPhotoClick}
        />
      ))}
    </group>
  );
};

import React, { useRef, useMemo, useEffect } from 'react';
import { useFrame, useThree } from '@react-three/fiber';
import { OrbitControls, Environment, PerspectiveCamera, Stars } from '@react-three/drei';
import { EffectComposer, Bloom, Vignette, Noise } from '@react-three/postprocessing';
import * as THREE from 'three';
import { FilesetResolver, HandLandmarker } from '@mediapipe/tasks-vision';
import { Foliage } from './Foliage';
import { Ornaments } from './Ornaments';
import { UserPhotos } from './UserPhotos';
import { Gifts } from './Gifts';
import { TreeState } from '../types';

// --- Base Sparkles (Fireflies) ---
const BaseSparkles = () => {
  const count = 200;
  const mesh = useRef<THREE.Points>(null);

  const { positions, randoms } = useMemo(() => {
    const pos = new Float32Array(count * 3);
    const rnd = new Float32Array(count);

    for (let i = 0; i < count; i++) {
        // Radius 10 to 20
        const r = 10 + Math.random() * 10; 
        const theta = Math.random() * Math.PI * 2;

        pos[i * 3] = r * Math.cos(theta); // x
        pos[i * 3 + 1] = -15 + Math.random() * 7; // y: -15 to -8
        pos[i * 3 + 2] = r * Math.sin(theta); // z

        rnd[i] = Math.random();
    }
    return { positions: pos, randoms: rnd };
  }, []);

  useFrame((state) => {
      if(mesh.current) {
          const time = state.clock.elapsedTime;
          // Gentle floating movement
          mesh.current.position.y = Math.sin(time * 0.2) * 0.5;
          mesh.current.rotation.y = time * 0.05;
      }
  });

  return (
      <points ref={mesh}>
          <bufferGeometry>
              <bufferAttribute attach="attributes-position" count={count} array={positions} itemSize={3} />
          </bufferGeometry>
          <pointsMaterial 
            size={0.15} 
            color="#FFEA00" 
            transparent 
            opacity={0.6} 
            blending={THREE.AdditiveBlending} 
            depthWrite={false}
          />
      </points>
  );
};

interface ExperienceProps {
  treeState: TreeState;
  setTreeState: (state: TreeState) => void;
  userPhotos: string[];
  focusedPhotoId: string | null;
  setFocusedPhotoId: (id: string | null) => void;
}

export const Experience: React.FC<ExperienceProps> = ({ 
  treeState, 
  setTreeState, 
  userPhotos,
  focusedPhotoId,
  setFocusedPhotoId
}) => {
  const cameraRef = useRef<THREE.PerspectiveCamera>(null);
  const groupRef = useRef<THREE.Group>(null);
  const starRef = useRef<THREE.Mesh>(null);

  // Hand Tracking Refs
  const videoRef = useRef<HTMLVideoElement | null>(null);
  const handLandmarkerRef = useRef<HandLandmarker | null>(null);
  const lastVideoTimeRef = useRef(-1);
  const targetRotation = useRef({ x: 0, y: 0 });

  // Setup MediaPipe
  useEffect(() => {
    let isMounted = true;

    const setupHandTracking = async () => {
      try {
        const vision = await FilesetResolver.forVisionTasks(
          "https://cdn.jsdelivr.net/npm/@mediapipe/tasks-vision@0.10.8/wasm"
        );

        if (!isMounted) return;

        const landmarker = await HandLandmarker.createFromOptions(vision, {
          baseOptions: {
            modelAssetPath: `https://storage.googleapis.com/mediapipe-models/hand_landmarker/hand_landmarker/float16/1/hand_landmarker.task`,
            delegate: "GPU"
          },
          runningMode: "VIDEO",
          numHands: 1
        });

        if (!isMounted) {
            landmarker.close();
            return;
        }

        handLandmarkerRef.current = landmarker;

        // Get Webcam
        const video = document.getElementById("webcam") as HTMLVideoElement;
        videoRef.current = video;

        if (navigator.mediaDevices && navigator.mediaDevices.getUserMedia) {
          const stream = await navigator.mediaDevices.getUserMedia({ 
            video: { 
              width: 1280, 
              height: 720 
            } 
          });

          if (!isMounted) {
            stream.getTracks().forEach(t => t.stop());
            return;
          }

          video.srcObject = stream;
          video.onloadedmetadata = () => {
            if (isMounted) video.play().catch(e => console.error("Video play error:", e));
          };
        }
      } catch (error) {
        console.error("Error initializing MediaPipe or Webcam:", error);
      }
    };

    setupHandTracking();

    // Cleanup function to handle Strict Mode unmounts
    return () => {
      isMounted = false;

      // Close Landmarker
      if (handLandmarkerRef.current) {
        handLandmarkerRef.current.close();
        handLandmarkerRef.current = null;
      }

      // Stop Camera Stream
      const video = document.getElementById("webcam") as HTMLVideoElement;
      if (video && video.srcObject) {
        const stream = video.srcObject as MediaStream;
        stream.getTracks().forEach(track => track.stop());
        video.srcObject = null;
      }
    };
  }, []);

  // Gesture Recognition Logic
  const detectGestures = (landmarks: any[]) => {
    const wrist = landmarks[0];
    const thumbTip = landmarks[4];
    const indexTip = landmarks[8];
    const midTip = landmarks[12];
    const ringTip = landmarks[16];
    const pinkyTip = landmarks[20];
    const handCenter = landmarks[9]; // Middle finger mcp

    // Distance Helper
    const dist = (p1: any, p2: any) => Math.sqrt(
      Math.pow(p1.x - p2.x, 2) + Math.pow(p1.y - p2.y, 2) + Math.pow(p1.z - p2.z, 2)
    );

    // 1. FIST Detection (Average distance from tips to wrist < 0.15)
    const tips = [indexTip, midTip, ringTip, pinkyTip];
    const avgDistToWrist = tips.reduce((acc, tip) => acc + dist(tip, wrist), 0) / 4;

    // 2. OPEN HAND Detection (Avg distance > 0.35)
    // 3. PINCH Detection (Thumb to Index < 0.05)
    const pinchDist = dist(thumbTip, indexTip);

    // --- State Machine Logic ---
    if (avgDistToWrist < 0.15) {
      if (treeState !== TreeState.TREE_SHAPE) setTreeState(TreeState.TREE_SHAPE);
    } 
    else if (avgDistToWrist > 0.35) {
      if (treeState !== TreeState.SCATTERED) setTreeState(TreeState.SCATTERED);
    }
    else if (pinchDist < 0.05) {
      if (treeState !== TreeState.FOCUS && userPhotos.length > 0) {
        setTreeState(TreeState.FOCUS);
        // Randomly select a photo
        const randomId = `photo-${Math.floor(Math.random() * userPhotos.length)}`;
        setFocusedPhotoId(randomId);
      }
    }

    // 4. HAND ROTATION (Active in SCATTER)
    // We only update target rotation if NOT in TREE_SHAPE, but usually only helpful in SCATTER
    if (treeState !== TreeState.TREE_SHAPE) {
       // Map X (0-1) to Rotation Y (-1.5 to 1.5 radians approx)
       // Map Y (0-1) to Rotation X
       // In MediaPipe, X is 0 (left) to 1 (right)
       targetRotation.current.y = (handCenter.x - 0.5) * 3.0; 
       targetRotation.current.x = (handCenter.y - 0.5) * 3.0; 
    } else {
        targetRotation.current.x = 0;
        targetRotation.current.y = 0; // Reset or let auto-spin handle it
    }
  };

  // Mouse Interaction Handler
  const handlePhotoClick = (id: string) => {
    setFocusedPhotoId(id);
    setTreeState(TreeState.FOCUS);
  };

  useFrame((state) => {
    // Process MediaPipe Frame with Strict Validation
    if (
      handLandmarkerRef.current && 
      videoRef.current && 
      videoRef.current.readyState >= 2 && // HAVE_CURRENT_DATA
      !videoRef.current.paused &&         // Video must be playing
      videoRef.current.videoWidth > 0 &&  // Strictly positive width
      videoRef.current.videoHeight > 0 && // Strictly positive height
      videoRef.current.currentTime !== lastVideoTimeRef.current
    ) {
        lastVideoTimeRef.current = videoRef.current.currentTime;
        try {
          const results = handLandmarkerRef.current.detectForVideo(videoRef.current, performance.now());

          if (results.landmarks && results.landmarks.length > 0) {
              detectGestures(results.landmarks[0]);
          }
        } catch (e) {
          // Swallow sporadic errors or graph crashes to prevent app freeze
          // console.warn("MediaPipe Detect Error:", e);
        }
    }

    // Animation Loop for Group Rotation
    if (groupRef.current) {
        if (treeState === TreeState.TREE_SHAPE) {
            // Default Auto Spin
            groupRef.current.rotation.y += 0.002;
            // Lerp back to 0 on X
            groupRef.current.rotation.x = THREE.MathUtils.lerp(groupRef.current.rotation.x, 0, 0.05);
        } else if (treeState === TreeState.FOCUS) {
            // MODE: FOCUS - Center the Group
            // Smoothly reset rotation to 0,0,0 so the coordinate system aligns with Camera
            groupRef.current.rotation.x = THREE.MathUtils.lerp(groupRef.current.rotation.x, 0, 0.1);
            groupRef.current.rotation.y = THREE.MathUtils.lerp(groupRef.current.rotation.y, 0, 0.1);
        } else {
            // MODE: SCATTER - Hand Controlled Rotation
            groupRef.current.rotation.y = THREE.MathUtils.lerp(groupRef.current.rotation.y, targetRotation.current.y, 0.05);
            groupRef.current.rotation.x = THREE.MathUtils.lerp(groupRef.current.rotation.x, targetRotation.current.x, 0.05);
        }
    }

    // Star Spin
    if (starRef.current) {
        starRef.current.rotation.y += 0.01;
    }
  });

  // Generate 5-pointed Star Shape
  const starShape = useMemo(() => {
    const shape = new THREE.Shape();
    const outerRadius = 1.5;
    const innerRadius = 0.7; // Depth of the star cuts
    const points = 5;

    for (let i = 0; i < points * 2; i++) {
      const angle = (i * Math.PI) / points;
      const radius = i % 2 === 0 ? outerRadius : innerRadius;
      const x = Math.cos(angle) * radius;
      const y = Math.sin(angle) * radius;
      if (i === 0) shape.moveTo(x, y);
      else shape.lineTo(x, y);
    }
    shape.closePath();
    return shape;
  }, []);

  const starExtrudeSettings = useMemo(() => ({
    depth: 0.5,
    bevelEnabled: true,
    bevelThickness: 0.1,
    bevelSize: 0.1,
    bevelSegments: 2
  }), []);

  return (
    <>
      <PerspectiveCamera makeDefault position={[0, 2, 25]} fov={50} ref={cameraRef} />

      <OrbitControls 
        enablePan={false} 
        minPolarAngle={Math.PI / 3} 
        maxPolarAngle={Math.PI / 1.8}
        minDistance={10}
        maxDistance={40}
      />

      {/* Lighting: Bright & Cheerful */}
      <ambientLight intensity={0.6} color="#ffffff" /> 
      <spotLight 
        position={[10, 20, 10]} 
        angle={0.5} 
        penumbra={1} 
        intensity={2} 
        color="#fff" 
        castShadow 
      />
      <pointLight position={[-10, 5, -10]} intensity={1.5} color="#FFEA00" />
      <pointLight position={[0, -5, 10]} intensity={0.5} color="#00BFFF" />

      <pointLight 
        position={[0, -12, 0]} 
        intensity={4.0} 
        distance={25} 
        color="#FFD700" 
        decay={2}
      />

      <Environment files="https://dl.polyhaven.org/file/ph-assets/HDRIs/hdr/1k/potsdamer_platz_1k.hdr" />
      <Stars radius={100} depth={50} count={5000} factor={4} saturation={0} fade speed={1} />

      <group ref={groupRef} position={[0, -4, 0]}>
        <BaseSparkles />
        <pointLight position={[0, 6, 0]} intensity={1} color="#FFD700" distance={10} decay={2} />

        <Foliage state={treeState} count={12000} />
        <Ornaments state={treeState} count={600} />
        <Gifts state={treeState} />

        {/* Pass click handler and props */}
        <UserPhotos 
            photos={userPhotos} 
            state={treeState} 
            focusedId={focusedPhotoId}
            onPhotoClick={handlePhotoClick}
        />

        <group position={[0, 6.5, 0]}>
            <mesh 
                ref={starRef} 
                scale={treeState === TreeState.TREE_SHAPE ? 1 : 0}
                rotation={[0, 0, Math.PI / 10]} 
            >
                <extrudeGeometry args={[starShape, starExtrudeSettings]} />
                <meshStandardMaterial 
                    color="#FFD700" 
                    emissive="#FFD700" 
                    emissiveIntensity={2.0} 
                    toneMapped={false}
                />
                <pointLight color="#FFD700" distance={30} intensity={5} decay={2} />
            </mesh>
        </group>
      </group>

      <EffectComposer disableNormalPass>
        <Bloom 
          luminanceThreshold={0.8} 
          mipmapBlur 
          intensity={1.2} 
          radius={0.5} 
        />
        <Vignette eskil={false} offset={0.1} darkness={1.0} />
        <Noise opacity={0.02} /> 
      </EffectComposer>
    </>
  );
};

import React, { useMemo, useRef, useEffect } from 'react';
import { useFrame, useLoader, useThree } from '@react-three/fiber';
import * as THREE from 'three';
import { getScatterPoint, getTreePoint, randomRange } from '../utils/math';
import { TreeState, UserPhotoData } from '../types';

interface UserPhotosProps {
  photos: string[];
  state: TreeState;
  focusedId: string | null;
  onPhotoClick: (id: string) => void;
}

// Sub-component for individual photo to handle texture loading gracefully
const PhotoFrame: React.FC<{ 
  data: UserPhotoData; 
  state: TreeState; 
  isFocused: boolean;
  onPhotoClick: (id: string) => void; 
}> = ({ data, state, isFocused, onPhotoClick }) => {
  const groupRef = useRef<THREE.Group>(null);
  const texture = useLoader(THREE.TextureLoader, data.url);
  const { gl, camera } = useThree();

  // New Ref for Zoom Interaction
  const focusDistance = useRef(15.0);

  // Dynamic Aspect Ratio Logic
  const { width, height } = texture.image;
  const aspect = width / height;
  const baseHeight = 2.0; // Base height standard
  const planeWidth = baseHeight * aspect;
  const framePadding = 0.4;
  const frameWidth = planeWidth + framePadding;
  const frameHeight = baseHeight + framePadding;

  // Fix Texture Flickering / Aliasing
  useEffect(() => {
    if (texture) {
      texture.generateMipmaps = true;
      texture.minFilter = THREE.LinearMipmapLinearFilter; 
      texture.magFilter = THREE.LinearFilter;
      texture.anisotropy = gl.capabilities.getMaxAnisotropy(); 
      texture.needsUpdate = true;
    }
  }, [texture, gl]);

  // Scroll to Zoom Listener
  useEffect(() => {
    if (!isFocused || state !== TreeState.FOCUS) return;

    // Reset distance when entering focus mode
    focusDistance.current = 15.0;

    const handleWheel = (e: WheelEvent) => {
      // Adjust sensitivity: e.deltaY is usually +/- 100
      const zoomSpeed = 0.02; 
      focusDistance.current = THREE.MathUtils.clamp(
        focusDistance.current + e.deltaY * zoomSpeed, 
        5.0, 
        40.0
      );
    };

    window.addEventListener('wheel', handleWheel);
    return () => window.removeEventListener('wheel', handleWheel);
  }, [isFocused, state]);

  useFrame((rootState, delta) => {
    if (!groupRef.current) return;

    const time = rootState.clock.elapsedTime;

    // --- STATE MACHINE ANIMATION LOGIC ---

    // We use Quaternions for rotation now to support smooth camera tracking (HUD mode)
    let targetPos = new THREE.Vector3();
    let targetRot = new THREE.Quaternion();
    let targetScale = 1.0;

    if (state === TreeState.FOCUS && isFocused) {
        // MODE C: FOCUS (HUD / Head-Locked)
        // The photo continuously tracks the camera to stay perfectly centered (Billboard).

        // 1. Calculate World Target Position
        // Use dynamic distance controlled by scroll
        const distance = focusDistance.current; 
        const forward = new THREE.Vector3();
        camera.getWorldDirection(forward);
        const targetWorldPos = camera.position.clone().add(forward.multiplyScalar(distance));

        // 2. Convert to Local Space
        // Since this group is a child of the rotating main tree group, 
        // we must convert the static world "HUD" coordinate into the parent's local space.
        if (groupRef.current.parent) {
            targetPos.copy(targetWorldPos);
            groupRef.current.parent.worldToLocal(targetPos);

            // 3. Orientation Calculation
            // We want the object's WORLD rotation to match the Camera's WORLD rotation.
            // Equation: ParentWorldQuat * LocalQuat = CameraWorldQuat
            // Solution: LocalQuat = inverse(ParentWorldQuat) * CameraWorldQuat

            const parentWorldQuat = new THREE.Quaternion();
            groupRef.current.parent.getWorldQuaternion(parentWorldQuat);

            targetRot.copy(camera.quaternion);
            targetRot.premultiply(parentWorldQuat.invert());
        } else {
            // Fallback (should not happen in this hierarchy)
            targetPos.copy(targetWorldPos);
            targetRot.copy(camera.quaternion);
        }

        // 4. Scale
        targetScale = 2.0; 

    } else if (state === TreeState.TREE_SHAPE) {
        // MODE A: TREE
        targetPos.copy(data.tree);

        // Convert stored Euler to Quaternion
        const euler = new THREE.Euler(data.rotation.x, data.rotation.y, data.rotation.z);
        targetRot.setFromEuler(euler);

        targetScale = data.scale;
    } else {
        // MODE B: SCATTER (Background)
        targetPos.copy(data.scatter);

        // Add floating noise for SCATTER mode
        targetPos.y += Math.sin(time * data.speed) * 0.5;
        targetPos.x += Math.cos(time * data.speed * 0.5) * 0.5;

        // Spin rotation (Animated Euler -> Quaternion)
        const euler = new THREE.Euler(
            data.rotation.x + (time * 0.2),
            data.rotation.y + (time * 0.3),
            data.rotation.z
        );
        targetRot.setFromEuler(euler);

        targetScale = data.scale;
    }

    // --- LERP TRANSITIONS ---
    // Use a factor of 0.1 for responsive but smooth tracking
    const lerpFactor = 0.1;

    groupRef.current.position.lerp(targetPos, lerpFactor);
    groupRef.current.quaternion.slerp(targetRot, lerpFactor);
    groupRef.current.scale.lerp(new THREE.Vector3(targetScale, targetScale, targetScale), lerpFactor);
  });

  return (
    <group 
      ref={groupRef}
      onClick={(e) => {
        e.stopPropagation(); // Stop raycast bubbling
        onPhotoClick(data.id);
      }}
      onPointerOver={() => document.body.style.cursor = 'pointer'}
      onPointerOut={() => document.body.style.cursor = 'auto'}
    >
      {/* Gold Frame - Dynamic Size */}
      {/* Centered at 0. Depth 0.2 means faces are at -0.1 and +0.1 */}
      <mesh position={[0, 0, 0]}>
        <boxGeometry args={[frameWidth, frameHeight, 0.2]} />
        <meshStandardMaterial 
            color="#D4AF37" 
            metalness={0.8} 
            roughness={0.2} 
            envMapIntensity={2} 
        />
      </mesh>

      {/* The Photo - Dynamic Size */}
      {/* Placed at +0.15 to strictly prevent Z-fighting with the frame's +0.1 face */}
      <mesh position={[0, 0, 0.15]}>
        <planeGeometry args={[planeWidth, baseHeight]} />
        <meshBasicMaterial map={texture} side={THREE.DoubleSide} />
      </mesh>
    </group>
  );
};

export const UserPhotos: React.FC<UserPhotosProps> = ({ photos, state, focusedId, onPhotoClick }) => {
  // Generate 3D data for photos only when the photo list changes
  const photosData = useMemo(() => {
    return photos.map((url, index) => {
      // Position photos in the middle-to-bottom section of the tree for better visibility
      const treePos = getTreePoint(10, 5, -5); 
      const radialDir = new THREE.Vector3(treePos.x, 0, treePos.z).normalize();
      treePos.add(radialDir.multiplyScalar(0.8));

      return {
        id: `photo-${index}`,
        url,
        tree: treePos,
        scatter: getScatterPoint(18),
        rotation: new THREE.Euler(0, Math.random() * Math.PI * 2, 0), 
        scale: randomRange(0.8, 1.2),
        speed: randomRange(0.5, 1.5),
      } as UserPhotoData;
    });
  }, [photos]);

  return (
    <group>
      {photosData.map((data) => (
        <PhotoFrame 
            key={data.id} 
            data={data} 
            state={state} 
            isFocused={focusedId === data.id}
            onPhotoClick={onPhotoClick}
        />
      ))}
    </group>
  );
};

import React, { useMemo, useRef, useLayoutEffect } from 'react';
import { useFrame } from '@react-three/fiber';
import * as THREE from 'three';
import { getScatterPoint, getTreePoint, randomRange } from '../utils/math';
import { TreeState, OrnamentData } from '../types';

const tempObj = new THREE.Object3D();
const tempVec3 = new THREE.Vector3();

// --- CONFIG: Hybrid Art Deco Palette ---
const CONFIG = {
  colors: {
    emerald: new THREE.Color('#023E28'), // Deep Forest Green (The "Beautiful Green")
    ruby: new THREE.Color('#852736'),    // Antique Ruby
    gold: new THREE.Color('#E2C99E'),    // Desert Sand (Champagne Gold)
    blue: new THREE.Color('#414B9E'),    // Chinese Blue
    purple: new THREE.Color('#AA74A0'),  // Pearly Purple
  }
};

interface OrnamentsProps {
  count?: number;
  state: TreeState;
}

export const Ornaments: React.FC<OrnamentsProps> = ({ count = 600, state }) => {
  // We need separate meshes for distinct material properties
  const goldRef = useRef<THREE.InstancedMesh>(null);
  const ceramicRef = useRef<THREE.InstancedMesh>(null);
  const satinRef = useRef<THREE.InstancedMesh>(null);
  const boxesRef = useRef<THREE.InstancedMesh>(null);

  // 1. GOLD (30%): Desert Sand
  const goldData = useMemo(() => 
    generateOrnamentData(Math.floor(count * 0.3), 'SPHERE', [CONFIG.colors.gold]), 
  [count]);

  // 2. CERAMIC (40%): Emerald & Ruby
  const ceramicData = useMemo(() => 
    generateOrnamentData(Math.floor(count * 0.4), 'SPHERE', [CONFIG.colors.emerald, CONFIG.colors.ruby]), 
  [count]);

  // 3. SATIN (30%): Blue & Purple
  const satinData = useMemo(() => 
    generateOrnamentData(Math.floor(count * 0.3), 'SPHERE', [CONFIG.colors.blue, CONFIG.colors.purple]), 
  [count]);

  // 4. Boxes (Small Gifts scattered on tree - Mix of Accent Colors)
  const boxData = useMemo(() => 
    generateOrnamentData(Math.floor(count * 0.15), 'BOX', [
      CONFIG.colors.gold, CONFIG.colors.ruby, CONFIG.colors.blue
    ]), 
  [count]);

  useLayoutEffect(() => {
    if (goldRef.current) applyColors(goldRef.current, goldData);
    if (ceramicRef.current) applyColors(ceramicRef.current, ceramicData);
    if (satinRef.current) applyColors(satinRef.current, satinData);
    if (boxesRef.current) applyColors(boxesRef.current, boxData);
  }, [goldData, ceramicData, satinData, boxData]);

  useFrame((rootState, delta) => {
    const time = rootState.clock.elapsedTime;
    const targetMorph = state === TreeState.TREE_SHAPE ? 1 : 0;

    updateInstances(goldRef.current, goldData, targetMorph, time, delta);
    updateInstances(ceramicRef.current, ceramicData, targetMorph, time, delta);
    updateInstances(satinRef.current, satinData, targetMorph, time, delta);
    updateInstances(boxesRef.current, boxData, targetMorph, time, delta);
  });

  return (
    <group>
      {/* 1. GOLD: High Shine Metallic (Desert Sand) */}
      <instancedMesh ref={goldRef} args={[undefined, undefined, goldData.length]}>
        <sphereGeometry args={[0.25, 32, 32]} />
        <meshStandardMaterial 
          metalness={0.9} 
          roughness={0.2} 
          envMapIntensity={1.5}
        />
      </instancedMesh>

      {/* 2. CERAMIC: Deep Colors (Emerald, Ruby) - High Gloss Enamel */}
      <instancedMesh ref={ceramicRef} args={[undefined, undefined, ceramicData.length]}>
        <sphereGeometry args={[0.25, 32, 32]} />
        <meshPhysicalMaterial 
          metalness={0.1} 
          roughness={0.3} 
          clearcoat={1.0}
          clearcoatRoughness={0.1}
          envMapIntensity={1.0}
        />
      </instancedMesh>

      {/* 3. SATIN: Soft Accents (Blue, Purple) */}
      <instancedMesh ref={satinRef} args={[undefined, undefined, satinData.length]}>
        <sphereGeometry args={[0.25, 32, 32]} />
        <meshStandardMaterial 
          metalness={0.3} 
          roughness={0.4} 
          envMapIntensity={1.0}
        />
      </instancedMesh>

      {/* 4. Boxes: Metallic Foil */}
      <instancedMesh ref={boxesRef} args={[undefined, undefined, boxData.length]}>
        <boxGeometry args={[0.4, 0.4, 0.4]} />
        <meshStandardMaterial 
          metalness={0.6} 
          roughness={0.3}
          envMapIntensity={1.2}
        />
      </instancedMesh>
    </group>
  );
};

// --- Helpers ---

function generateOrnamentData(count: number, type: 'SPHERE' | 'BOX', colorPalette: THREE.Color[]): OrnamentData[] {
  const data: OrnamentData[] = [];

  for (let i = 0; i < count; i++) {
    const treePos = getTreePoint(12, 5.0, -6);
    // Push ornaments slightly outward so they sit ON the leaves, not inside
    const radialDir = new THREE.Vector3(treePos.x, 0, treePos.z).normalize();
    treePos.add(radialDir.multiplyScalar(0.4)); 

    const scatterPos = getScatterPoint(20);

    data.push({
      type,
      tree: treePos,
      scatter: scatterPos,
      rotation: new THREE.Euler(Math.random() * Math.PI, Math.random() * Math.PI, 0),
      scale: randomRange(0.8, 1.5),
      speed: randomRange(0.5, 2.0),
      color: colorPalette[Math.floor(Math.random() * colorPalette.length)]
    });
  }
  return data;
}

function applyColors(mesh: THREE.InstancedMesh, data: OrnamentData[]) {
  for (let i = 0; i < data.length; i++) {
    mesh.setColorAt(i, data[i].color);
  }
  mesh.instanceColor!.needsUpdate = true;
}

function updateInstances(
  mesh: THREE.InstancedMesh | null, 
  data: OrnamentData[], 
  targetMorph: number, 
  time: number,
  delta: number
) {
  if (!mesh) return;

  if (mesh.userData.morphValue === undefined) mesh.userData.morphValue = 0;

  const speed = 1.5;
  mesh.userData.morphValue = THREE.MathUtils.lerp(mesh.userData.morphValue, targetMorph, speed * delta);
  const t = mesh.userData.morphValue;

  for (let i = 0; i < data.length; i++) {
    const item = data[i];

    // Position Mix
    tempVec3.lerpVectors(item.scatter, item.tree, t);

    // Add noise/floating
    const floatAmp = (1 - t) * 0.5; // Floats more when scattered
    tempVec3.y += Math.sin(time * item.speed + i) * floatAmp;
    tempVec3.x += Math.cos(time * item.speed * 0.5 + i) * floatAmp;

    // Rotation
    // Spin when scattered, stabilize when tree
    const rotX = item.rotation.x + (time * 0.2 * (1 - t));
    const rotY = item.rotation.y + (time * 0.5 * (1 - t));

    tempObj.position.copy(tempVec3);
    tempObj.rotation.set(rotX, rotY, item.rotation.z);
    tempObj.scale.setScalar(item.scale * (t * 0.5 + 0.5)); // Grow slightly when forming tree

    tempObj.updateMatrix();
    mesh.setMatrixAt(i, tempObj.matrix);
  }
  mesh.instanceMatrix.needsUpdate = true;
}

import React, { useMemo, useRef } from 'react';
import { useFrame } from '@react-three/fiber';
import * as THREE from 'three';
import { getScatterPoint, getTreePoint, TREE_HEIGHT } from '../utils/math';
import { TreeState } from '../types';

// Custom Shader Material for the Foliage
// Updated Colors: Base = Deep Forest Green (#023E28), Tip = Desert Sand (#E2C99E)
const FoliageShaderMaterial = {
  uniforms: {
    uTime: { value: 0 },
    uMorphFactor: { value: 0 }, // 0 = Scatter, 1 = Tree
    uColorBase: { value: new THREE.Color('#023E28') }, // Deep Forest Green
    uColorTip: { value: new THREE.Color('#E2C99E') },  // Desert Sand (Gold)
  },
  vertexShader: `
    uniform float uTime;
    uniform float uMorphFactor;
    attribute vec3 aTreePosition;
    attribute vec3 aScatterPosition;
    attribute float aRandom;
    attribute float aSize;

    varying vec3 vColor;
    varying float vAlpha;

    // Cubic easing for smoother transition
    float easeInOutCubic(float x) {
      return x < 0.5 ? 4.0 * x * x * x : 1.0 - pow(-2.0 * x + 2.0, 3.0) / 2.0;
    }

    void main() {
      // Ease the morph factor
      float t = easeInOutCubic(uMorphFactor);

      // Mix positions based on morph factor
      vec3 targetPos = mix(aScatterPosition, aTreePosition, t);

      // Add "Breathing" / "Floating" animation
      float noiseAmp = mix(1.0, 0.2, t); 
      targetPos.x += sin(uTime * 1.5 + aRandom * 10.0) * 0.1 * noiseAmp;
      targetPos.y += cos(uTime * 1.2 + aRandom * 20.0) * 0.1 * noiseAmp;
      targetPos.z += sin(uTime * 1.8 + aRandom * 5.0) * 0.1 * noiseAmp;

      vec4 mvPosition = modelViewMatrix * vec4(targetPos, 1.0);
      gl_Position = projectionMatrix * mvPosition;

      // Size attenuation
      gl_PointSize = aSize * (300.0 / -mvPosition.z);

      // Pass randomness to fragment
      vAlpha = 0.6 + 0.4 * sin(uTime * 2.0 + aRandom * 100.0);
    }
  `,
  fragmentShader: `
    uniform vec3 uColorBase;
    uniform vec3 uColorTip;
    varying float vAlpha;

    void main() {
      // Create a soft circular particle
      vec2 coord = gl_PointCoord - vec2(0.5);
      float dist = length(coord);

      if (dist > 0.5) discard;

      // Soft glow gradient
      float strength = 1.0 - (dist * 2.0);
      strength = pow(strength, 1.5);

      // Mix colors 
      vec3 color = mix(uColorBase, uColorTip, strength * 0.5);

      // Add extra brightness for bloom
      gl_FragColor = vec4(color * 2.0, vAlpha * strength);
    }
  `
};

interface FoliageProps {
  count?: number;
  state: TreeState;
}

export const Foliage: React.FC<FoliageProps> = ({ count = 6000, state }) => {
  const shaderRef = useRef<THREE.ShaderMaterial>(null);

  // Generate data once
  const { positions, treePositions, scatterPositions, randoms, sizes } = useMemo(() => {
    const positions = new Float32Array(count * 3);
    const treePositions = new Float32Array(count * 3);
    const scatterPositions = new Float32Array(count * 3);
    const randoms = new Float32Array(count);
    const sizes = new Float32Array(count);

    const yOffset = -TREE_HEIGHT / 2;

    for (let i = 0; i < count; i++) {
      // Tree coords
      const tPos = getTreePoint();
      treePositions[i * 3] = tPos.x;
      treePositions[i * 3 + 1] = tPos.y;
      treePositions[i * 3 + 2] = tPos.z;

      // Scatter coords
      const sPos = getScatterPoint();
      scatterPositions[i * 3] = sPos.x;
      scatterPositions[i * 3 + 1] = sPos.y;
      scatterPositions[i * 3 + 2] = sPos.z;

      randoms[i] = Math.random();

      // Size Gradient Logic
      const h = (tPos.y - yOffset) / TREE_HEIGHT;
      const scaleGradient = 0.8 + 0.4 * (1 - h);

      sizes[i] = (Math.random() * 0.5 + 0.2) * scaleGradient;
    }

    return { positions, treePositions, scatterPositions, randoms, sizes };
  }, [count]);

  useFrame((stateThree, delta) => {
    if (shaderRef.current) {
      shaderRef.current.uniforms.uTime.value = stateThree.clock.elapsedTime;

      const targetFactor = state === TreeState.TREE_SHAPE ? 1.0 : 0.0;
      const currentFactor = shaderRef.current.uniforms.uMorphFactor.value;
      const speed = 2.0;

      shaderRef.current.uniforms.uMorphFactor.value = THREE.MathUtils.lerp(
        currentFactor,
        targetFactor,
        speed * delta
      );
    }
  });

  return (
    <points>
      <bufferGeometry>
        <bufferAttribute
          attach="attributes-position"
          count={positions.length / 3}
          array={positions} 
          itemSize={3}
        />
        <bufferAttribute
          attach="attributes-aTreePosition"
          count={treePositions.length / 3}
          array={treePositions}
          itemSize={3}
        />
        <bufferAttribute
          attach="attributes-aScatterPosition"
          count={scatterPositions.length / 3}
          array={scatterPositions}
          itemSize={3}
        />
        <bufferAttribute
          attach="attributes-aRandom"
          count={randoms.length}
          array={randoms}
          itemSize={1}
        />
        <bufferAttribute
          attach="attributes-aSize"
          count={sizes.length}
          array={sizes}
          itemSize={1}
        />
      </bufferGeometry>
      <shaderMaterial
        ref={shaderRef}
        args={[FoliageShaderMaterial]}
        transparent
        depthWrite={false}
        blending={THREE.AdditiveBlending}
      />
    </points>
  );
};

import React, { useMemo, useRef, useLayoutEffect } from 'react';
import { useFrame } from '@react-three/fiber';
import * as THREE from 'three';
import { getScatterPoint, randomRange, TREE_HEIGHT, TREE_RADIUS_BOTTOM } from '../utils/math';
import { TreeState, OrnamentData } from '../types';

const tempObj = new THREE.Object3D();
const tempVec3 = new THREE.Vector3();

interface GiftsProps {
  state: TreeState;
}

export const Gifts: React.FC<GiftsProps> = ({ state }) => {
  const meshRef = useRef<THREE.InstancedMesh>(null);
  const count = 40;

  const data = useMemo(() => {
    const d: OrnamentData[] = [];
    // Urban Sunset Palette (Updated to Art Deco Luxury)
    const colors = [
      new THREE.Color('#414B9E'), // Chinese Blue
      new THREE.Color('#9792CB'), // Ceil (kept for variety or replace with Purple)
      new THREE.Color('#AA74A0'), // Pearly Purple
      new THREE.Color('#E2C99E'), // Desert Sand
      new THREE.Color('#852736'), // Antique Ruby
      new THREE.Color('#023E28'), // Deep Emerald (Added)
    ];

    const bottomY = -TREE_HEIGHT / 2; // -6

    for (let i = 0; i < count; i++) {
      // Scatter Logic (same as ornaments)
      const scatterPos = getScatterPoint(20);

      // Tree Logic (Base Cluster)
      const r = randomRange(2, TREE_RADIUS_BOTTOM + 2);
      const theta = Math.random() * Math.PI * 2;
      const x = r * Math.cos(theta);
      const z = r * Math.sin(theta);
      const y = bottomY + Math.random() * 2; // -6 to -4

      const treePos = new THREE.Vector3(x, y, z);

      d.push({
        type: 'BOX',
        tree: treePos,
        scatter: scatterPos,
        rotation: new THREE.Euler(0, Math.random() * Math.PI * 2, 0),
        scale: randomRange(1.0, 1.5), 
        speed: randomRange(0.5, 1.5),
        color: colors[Math.floor(Math.random() * colors.length)]
      });
    }
    return d;
  }, []);

  useLayoutEffect(() => {
    if (meshRef.current) {
      for (let i = 0; i < data.length; i++) {
        meshRef.current.setColorAt(i, data[i].color);
      }
      meshRef.current.instanceColor!.needsUpdate = true;
    }
  }, [data]);

  useFrame((stateThree, delta) => {
    if (!meshRef.current) return;

    // Smooth transition
    const targetMorph = state === TreeState.TREE_SHAPE ? 1 : 0;

    if (meshRef.current.userData.morphValue === undefined) meshRef.current.userData.morphValue = 0;
    meshRef.current.userData.morphValue = THREE.MathUtils.lerp(
      meshRef.current.userData.morphValue, 
      targetMorph, 
      1.5 * delta
    );
    const t = meshRef.current.userData.morphValue;
    const time = stateThree.clock.elapsedTime;

    for (let i = 0; i < data.length; i++) {
      const item = data[i];

      // Position
      tempVec3.lerpVectors(item.scatter, item.tree, t);

      // Float when scattered
      if (t < 0.99) {
          tempVec3.y += Math.sin(time * item.speed + i) * 0.2 * (1 - t);
      }

      const rotY = item.rotation.y + (time * 0.5 * (1 - t));

      tempObj.position.copy(tempVec3);
      tempObj.rotation.set(item.rotation.x * (1-t), rotY, item.rotation.z * (1-t));
      tempObj.scale.setScalar(item.scale);

      tempObj.updateMatrix();
      meshRef.current.setMatrixAt(i, tempObj.matrix);
    }
    meshRef.current.instanceMatrix.needsUpdate = true;
  });

  return (
    <instancedMesh ref={meshRef} args={[undefined, undefined, count]}>
      <boxGeometry args={[0.8, 0.8, 0.8]} /> 
      {/* Satin Finish for Gifts */}
      <meshStandardMaterial 
        metalness={0.2} 
        roughness={0.5}
        envMapIntensity={1.0}
      />
    </instancedMesh>
  );
};

